// ============================================================
// PSI EXTRACTOR & MERGER — Production v1.0
// Node name in n8n: "PSI Extractor"
// Place AFTER "Page Speed Insights" HTTP node
//       BEFORE "Report Builder2"
//
// This node:
//  1. Reads the PSI API response from the HTTP node (current input)
//  2. Reads the audit JSON from "SEO Audit Parser1" node by reference
//  3. Extracts all key PSI metrics, scores, and opportunities
//  4. Merges PSI data INTO the audit JSON
//  5. Outputs a single complete audit+psi object for the Report Builder
//
// CWV Thresholds (Google Official):
//  LCP:  Good < 2500ms | Needs Improvement 2500-4000ms | Poor > 4000ms
//  CLS:  Good < 0.1    | Needs Improvement 0.1-0.25    | Poor > 0.25
//  TBT:  Good < 200ms  | Needs Improvement 200-600ms   | Poor > 600ms
//  FCP:  Good < 1800ms | Needs Improvement 1800-3000ms | Poor > 3000ms
//  TTFB: Good < 800ms  | Needs Improvement 800-1800ms  | Poor > 1800ms
//  SI:   Good < 3400ms | Needs Improvement 3400-5800ms | Poor > 5800ms
// ============================================================

// Get PSI response from HTTP node (current node input)
const httpResponse = $input.first().json;

// Handle both n8n wrapper format {body, headers, statusCode}
// and direct response format
const psiBody = httpResponse.body || httpResponse;
const lr      = psiBody.lighthouseResult || {};
const audits  = lr.audits || {};
const cats    = lr.categories || {};
const loadExp = psiBody.loadingExperience || {};
const cfgSettings = lr.configSettings || {};

// Get audit JSON from parser node (by node reference)
// IMPORTANT: change "SEO Audit Parser" if your node has a different name
let audit;
try {
  audit = $('SEO Audit Parser').first().json;
} catch (e) {
  throw new Error('Cannot find SEO Audit Parser1 output. Make sure the parser node is named exactly "SEO Audit Parser1" and has run successfully.');
}

// ── HELPER FUNCTIONS ──
const safeScore = (score) => score !== null && score !== undefined ? Math.round(score * 100) : null;
const safeMs    = (val) => val ? Math.round(val) : 0;

// CWV threshold classifier
function cwvStatus(metric, value) {
  const thresholds = {
    lcp:  [2500, 4000],
    cls:  [0.1, 0.25],
    tbt:  [200, 600],
    fcp:  [1800, 3000],
    ttfb: [800, 1800],
    si:   [3400, 5800],
    tti:  [3800, 7300],
    fid:  [100, 300],
  };
  const t = thresholds[metric];
  if (!t || value === null || value === undefined) return 'unknown';
  if (value <= t[0]) return 'good';
  if (value <= t[1]) return 'needs_improvement';
  return 'poor';
}

// ── EXTRACT METRICS ──
const metricsItems = audits.metrics?.details?.items || [{}];
const m = metricsItems[0] || {};

// Core Web Vitals (Lab data from Lighthouse)
const lcp_ms   = safeMs(m.largestContentfulPaint);
const fcp_ms   = safeMs(m.firstContentfulPaint);
const tbt_ms   = safeMs(m.totalBlockingTime);
const cls_val  = parseFloat((m.cumulativeLayoutShift || 0).toFixed(4));
const si_ms    = safeMs(m.speedIndex);
const tti_ms   = safeMs(m.interactive);
const ttfb_ms  = safeMs(m.timeToFirstByte);

// ── EXTRACT FIELD DATA (CrUX) IF AVAILABLE ──
const fieldMetrics = loadExp.metrics || {};
const fieldLCP = fieldMetrics.LARGEST_CONTENTFUL_PAINT_MS;
const fieldFID = fieldMetrics.FIRST_INPUT_DELAY_MS;
const fieldCLS = fieldMetrics.CUMULATIVE_LAYOUT_SHIFT_SCORE;
const fieldINP = fieldMetrics.INTERACTION_TO_NEXT_PAINT;
const fieldFCP = fieldMetrics.FIRST_CONTENTFUL_PAINT_MS;
const fieldTTFB = fieldMetrics.EXPERIMENTAL_TIME_TO_FIRST_BYTE || fieldMetrics.TIME_TO_FIRST_BYTE_MS;

// ── EXTRACT OPPORTUNITIES ──
// Unused JS
const unusedJsAudit  = audits['unused-javascript'] || {};
const unusedCssAudit = audits['unused-css-rules']  || {};
const renderBlkAudit = audits['render-blocking-insight'] || audits['render-blocking-resources'] || {};
const cacheAudit     = audits['cache-insight'] || audits['uses-long-cache-ttl'] || {};
const largeImages    = audits['uses-responsive-images'] || audits['uses-optimized-images'] || {};
const unusedImages   = audits['offscreen-images'] || {};
const textCompress   = audits['uses-text-compression'] || {};
const webpImages     = audits['uses-webp-images'] || {};

// Opportunity savings
const totalOpportunitySavingsMs = [
  unusedJsAudit.metricSavings?.LCP || 0,
  unusedCssAudit.metricSavings?.LCP || 0,
  renderBlkAudit.numericValue || 0,
].reduce((a, b) => a + b, 0);

// ── RESOURCE SUMMARY ──
const rsItems = audits['resource-summary']?.details?.items || [];
const totalItem = rsItems.find(i => i.resourceType === 'total') || {};
const resourceBreakdown = rsItems
  .filter(i => i.resourceType !== 'total' && i.requestCount > 0)
  .map(i => ({ type: i.label, requests: i.requestCount, size_kb: Math.round(i.transferSize / 1024) }));

// ── DIAGNOSTICS ──
const longTasksDisplay  = audits['long-tasks']?.displayValue || '0';
const layoutShiftsDisplay = audits['layout-shifts']?.displayValue || '0';
const mainThreadMs = Math.round(parseFloat(audits['mainthread-work-breakdown']?.displayValue || '0') * 1000);
const jsBootupMs   = safeMs(audits['bootup-time']?.numericValue);
const domSize      = safeMs(audits['dom-size']?.numericValue);
const totalWeight  = safeMs(audits['total-byte-weight']?.numericValue);

// ── UNSIZED IMAGES ──
const unsizedImages = (audits['unsized-images']?.details?.items || []).slice(0, 5).map(i => ({
  url: i.url || '', selector: i.node?.selector || ''
}));

// ── LCP ELEMENT ──
let lcpElement = '';
let lcpIssue   = '';
const lcpDiscovery = audits['lcp-discovery-insight'] || {};
const lcpItems = lcpDiscovery.details?.items || [];
if (lcpItems.length > 0) {
  // First item has properties, second has the element details
  const props = lcpItems[0]?.items;
  if (props?.priorityHinted?.value === false) lcpIssue += 'Missing fetchpriority=high. ';
  if (lcpItems[1]?.snippet) lcpElement = lcpItems[1].snippet.substring(0, 100);
  else if (lcpItems[1]?.selector) lcpElement = lcpItems[1].selector;
}

// LCP breakdown timing
const lcpBreakdown = [];
const lbItems = audits['lcp-breakdown-insight']?.details?.items || [];
if (lbItems[0]?.items) {
  lbItems[0].items.forEach(part => {
    lcpBreakdown.push({ label: part.label, duration_ms: Math.round(part.duration) });
  });
}

// ── BUILD PSI OBJECT ──
const psi = {
  // Meta
  tested_url:          lr.requestedUrl || audit.meta.website,
  fetch_time:          lr.fetchTime || '',
  strategy:            cfgSettings.formFactor || cfgSettings.emulatedFormFactor || 'mobile',
  lighthouse_version:  lr.lighthouseVersion || '',

  // Overall performance score
  performance_score:   safeScore(cats.performance?.score),

  // Core Web Vitals — Lab (Lighthouse)
  lcp: {
    ms:           lcp_ms,
    display:      audits['largest-contentful-paint']?.displayValue || `${(lcp_ms/1000).toFixed(1)} s`,
    score:        safeScore(audits['largest-contentful-paint']?.score),
    status:       cwvStatus('lcp', lcp_ms),
    element:      lcpElement,
    issue:        lcpIssue,
    breakdown:    lcpBreakdown,
  },
  fcp: {
    ms:      fcp_ms,
    display: audits['first-contentful-paint']?.displayValue || `${(fcp_ms/1000).toFixed(1)} s`,
    score:   safeScore(audits['first-contentful-paint']?.score),
    status:  cwvStatus('fcp', fcp_ms),
  },
  tbt: {
    ms:      tbt_ms,
    display: audits['total-blocking-time']?.displayValue || `${tbt_ms} ms`,
    score:   safeScore(audits['total-blocking-time']?.score),
    status:  cwvStatus('tbt', tbt_ms),
  },
  cls: {
    value:   cls_val,
    display: audits['cumulative-layout-shift']?.displayValue || cls_val.toFixed(3),
    score:   safeScore(audits['cumulative-layout-shift']?.score),
    status:  cwvStatus('cls', cls_val),
    shifts:  parseInt(layoutShiftsDisplay) || 0,
  },
  si: {
    ms:      si_ms,
    display: audits['speed-index']?.displayValue || `${(si_ms/1000).toFixed(1)} s`,
    score:   safeScore(audits['speed-index']?.score),
    status:  cwvStatus('si', si_ms),
  },
  tti: {
    ms:      tti_ms,
    display: audits['interactive']?.displayValue || `${(tti_ms/1000).toFixed(1)} s`,
    score:   safeScore(audits['interactive']?.score),
    status:  cwvStatus('tti', tti_ms),
  },
  ttfb: {
    ms:      ttfb_ms,
    display: `${ttfb_ms} ms`,
    status:  cwvStatus('ttfb', ttfb_ms),
    raw_display: audits['server-response-time']?.displayValue || `${ttfb_ms} ms`,
  },

  // Field data (CrUX — real users, may not be available for small sites)
  field_data_available: loadExp.overall_category ? true : false,
  field_overall:        loadExp.overall_category || null,
  field_lcp:            fieldLCP ? { percentile: fieldLCP.percentile, category: fieldLCP.category } : null,
  field_fid:            fieldFID ? { percentile: fieldFID.percentile, category: fieldFID.category } : null,
  field_cls:            fieldCLS ? { percentile: fieldCLS.percentile, category: fieldCLS.category } : null,
  field_inp:            fieldINP ? { percentile: fieldINP.percentile, category: fieldINP.category } : null,

  // Opportunities
  opportunities: {
    unused_javascript: {
      savings_kb:  Math.round((unusedJsAudit.numericValue || 0) / 1024),
      savings_lcp_ms: unusedJsAudit.metricSavings?.LCP || 0,
      display:     unusedJsAudit.displayValue || '',
      score:       unusedJsAudit.score,
      items:       (unusedJsAudit.details?.items || []).slice(0, 5).map(i => ({
        url: i.url || '', savings_kb: Math.round((i.wastedBytes || 0) / 1024)
      }))
    },
    unused_css: {
      savings_kb: Math.round((unusedCssAudit.numericValue || 0) / 1024),
      display:    unusedCssAudit.displayValue || '',
      score:      unusedCssAudit.score,
      items:      (unusedCssAudit.details?.items || []).slice(0, 5).map(i => ({
        url: i.url || '', savings_kb: Math.round((i.wastedBytes || 0) / 1024)
      }))
    },
    render_blocking: {
      savings_ms: Math.round(renderBlkAudit.numericValue || 0),
      display:    renderBlkAudit.displayValue || '',
      score:      renderBlkAudit.score,
      items:      (renderBlkAudit.details?.items || []).slice(0, 8).map(i => ({
        url: i.url || '', wasted_ms: Math.round(i.wastedMs || 0),
        size_kb: Math.round((i.totalBytes || 0) / 1024)
      }))
    },
    cache_policy: {
      savings_kb: Math.round((cacheAudit.numericValue || 0) / 1024),
      display:    cacheAudit.displayValue || '',
      score:      cacheAudit.score,
    },
    total_potential_lcp_savings_ms: Math.round(totalOpportunitySavingsMs),
  },

  // Diagnostics
  diagnostics: {
    long_tasks:         parseInt(longTasksDisplay) || 0,
    layout_shifts:      parseInt(layoutShiftsDisplay) || 0,
    main_thread_ms:     mainThreadMs,
    js_execution_ms:    jsBootupMs,
    total_requests:     totalItem.requestCount || 0,
    total_size_kb:      Math.round((totalItem.transferSize || totalWeight || 0) / 1024),
    unsized_images:     unsizedImages,
  },

  // Page weight breakdown
  resource_breakdown: resourceBreakdown,
};

// ── MERGE PSI INTO AUDIT ──
const fullAudit = {
  ...audit,
  psi,
};

return [{ json: fullAudit }];

// ================================================================
// SEO AUDIT PARSER — Production v5.3
// FIXES FROM REPORT OVERVIEW REVIEW:
//
//  FIX 1: real4xxCount — was broken_link_sources.length (capped at 25)
//          now = getCount('response_codes_client_error_(4xx).csv')
//          → Cover and health score now show 111, not 25
//
//  FIX 2: broken_link_sources — now includes ALL 4xx (internal + external)
//          separated by issue_type field: 'Internal 404' or 'External 404'
//          Table shows top 25 by inlinks across both categories
//
//  FIX 3: Thin content threshold standardised to 300 words everywhere
//          (was 200 in issue card label, 300 in parser logic — now consistent)
//
//  FIX 4: Depth buckets — crawlOverview.depth used as primary source,
//          falls back to iStats.depthBuckets if crawl_overview has 0s
//
//  FIX 5: Health score 4xx — uses raw SF 4xx count (all 4xx, not just 25)
//
//  UNCHANGED: Everything else from v5.1 — all fields preserved
// ================================================================

const item   = $input.first();
const binary = item.binary;
if (!binary) throw new Error('No binary data. Check Compression node is connected.');

// ── Line parser ──────────────────────────────────────────────
function parseLine(line) {
  const result = [];
  let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') {
      if (inQ && line[i + 1] === '"') { cur += '"'; i++; }
      else inQ = !inQ;
    } else if (c === ',' && !inQ) { result.push(cur.trim()); cur = ''; }
    else { cur += c; }
  }
  result.push(cur.trim());
  return result;
}

// ── Chunk-based CSV parser ────────────────────────────────────
function parseCSVFromBuffer(buffer, maxRows = 99999, earlyExit = false) {
  const CHUNK = 65536;
  const headers = [], rows = [];
  let totalRows = 0, hParsed = false, rem = '';
  let start = (buffer.length >= 3 && buffer[0] === 0xEF && buffer[1] === 0xBB && buffer[2] === 0xBF) ? 3 : 0;

  for (let off = start; off < buffer.length; off += CHUNK) {
    const chunk    = buffer.slice(off, Math.min(off + CHUNK, buffer.length)).toString('utf-8');
    const combined = rem + chunk;
    const nli      = combined.lastIndexOf('\n');
    if (nli === -1) { rem = combined; continue; }
    const lines = combined.substring(0, nli + 1).split('\n');
    rem = combined.substring(nli + 1);
    for (const raw of lines) {
      const line = raw.replace(/\r$/, '').trim();
      if (!line) continue;
      if (!hParsed) { parseLine(line).forEach(h => headers.push(h.replace(/^\uFEFF/, ''))); hParsed = true; }
      else {
        totalRows++;
        if (rows.length < maxRows) {
          const vals = parseLine(line);
          const obj  = {};
          headers.forEach((h, i) => { obj[h] = (vals[i] ?? '').trim(); });
          rows.push(obj);
        } else if (earlyExit) { return { headers, rows, totalRows: rows.length }; }
      }
    }
  }
  if (rem.trim() && hParsed) {
    totalRows++;
    if (rows.length < maxRows) {
      const vals = parseLine(rem.replace(/\r$/, '').trim());
      const obj  = {};
      headers.forEach((h, i) => { obj[h] = (vals[i] ?? '').trim(); });
      rows.push(obj);
    }
  }
  return { headers, rows, totalRows };
}

// ── Streaming internal_html aggregator ───────────────────────
function processInternalHTML(buffer) {
  const CHUNK = 65536;
  let headers = null, ci = {}, hParsed = false;
  let totalRows = 0, sumRT = 0, sumWC = 0;
  let indexableCount = 0, nonIndexableCount = 0, h1 = 0, h2 = 0;
  const speedBuckets = { excellent:0, good:0, needs_work:0, slow:0, critical:0 };
  const wcBuckets    = { empty:0, thin:0, medium:0, good:0, rich:0 };
  const depthBuckets = { d1:0, d2:0, d3:0, d4:0, d5plus:0 };
  const slowestArr   = [], orphanArr = [], thinArr = [];

  const sf = v => { const n = parseFloat(v || '0'); return isNaN(n) ? 0 : n; };
  const si = v => { const n = parseInt(v   || '0'); return isNaN(n) ? 0 : n; };

  function processRow(vals) {
    if (!vals || vals.length < 2) return;
    const rt      = sf(vals[ci.rt]);
    const wc      = si(vals[ci.wc]);
    const depth   = si(vals[ci.depth]);
    const inlinks = si(ci.inlinks >= 0 ? vals[ci.inlinks] : (ci.uInlinks >= 0 ? vals[ci.uInlinks] : '0'));
    const hv      = (ci.hv      >= 0 ? vals[ci.hv]      : '') || '';
    const url     = (ci.url     >= 0 ? vals[ci.url]     : '') || '';
    const idx     = (ci.idx     >= 0 ? vals[ci.idx]     : '') || '';
    const status  = si(ci.status >= 0 ? vals[ci.status] : '0');
    const content = (ci.content >= 0 ? vals[ci.content] : '') || '';
    const sizeB   = si(ci.size   >= 0 ? vals[ci.size]   : '0');

    totalRows++; sumRT += rt; sumWC += wc;
    if      (idx === 'Indexable')     indexableCount++;
    else if (idx === 'Non-Indexable') nonIndexableCount++;

    if      (rt < 0.2) speedBuckets.excellent++;
    else if (rt < 0.5) speedBuckets.good++;
    else if (rt < 1.0) speedBuckets.needs_work++;
    else if (rt < 2.0) speedBuckets.slow++;
    else               speedBuckets.critical++;

    if (rt >= 1.5 && slowestArr.length < 500) slowestArr.push({ url, rt: rt.toFixed(3), size_kb: Math.round(sizeB / 1024) });

    const isHtml = !content || content.toLowerCase().includes('html');
    if (isHtml) {
      if      (wc === 0)   wcBuckets.empty++;
      else if (wc <= 200)  wcBuckets.thin++;
      else if (wc <= 600)  wcBuckets.medium++;
      else if (wc <= 1500) wcBuckets.good++;
      else                 wcBuckets.rich++;
      // FIX: threshold = 300 words (consistent everywhere)
      if (wc > 0 && wc < 300 && status === 200 && idx === 'Indexable' && thinArr.length < 500)
        thinArr.push({ url, word_count: wc });
    }

    if      (depth <= 1)  depthBuckets.d1++;
    else if (depth === 2) depthBuckets.d2++;
    else if (depth === 3) depthBuckets.d3++;
    else if (depth === 4) depthBuckets.d4++;
    else                  depthBuckets.d5plus++;

    if (inlinks === 0 && idx === 'Indexable' && status === 200 && url && isHtml && orphanArr.length < 500)
      orphanArr.push({ url, word_count: wc, depth });

    if (hv.includes('2')) h2++; else h1++;
  }

  let rem = '', start = (buffer.length >= 3 && buffer[0] === 0xEF && buffer[1] === 0xBB && buffer[2] === 0xBF) ? 3 : 0;

  for (let off = start; off < buffer.length; off += CHUNK) {
    const chunk    = buffer.slice(off, Math.min(off + CHUNK, buffer.length)).toString('utf-8');
    const combined = rem + chunk;
    const nli      = combined.lastIndexOf('\n');
    if (nli === -1) { rem = combined; continue; }
    const lines = combined.substring(0, nli + 1).split('\n');
    rem = combined.substring(nli + 1);
    for (const raw of lines) {
      const line = raw.replace(/\r$/, '').trim();
      if (!line) continue;
      if (!hParsed) {
        headers = parseLine(line);
        const fi = (...names) => { for (const n of names) { const i = headers.indexOf(n); if (i !== -1) return i; } return -1; };
        ci = {
          url:      fi('Address'),
          rt:       fi('Response Time'),
          wc:       fi('Word Count'),
          depth:    fi('Crawl Depth'),
          inlinks:  fi('Inlinks'),
          uInlinks: fi('Unique Inlinks'),
          hv:       fi('HTTP Version'),
          idx:      fi('Indexability'),
          status:   fi('Status Code'),
          content:  fi('Content'),
          size:     fi('Size (bytes)'),
        };
        hParsed = true;
      } else { processRow(parseLine(line)); }
    }
  }
  if (rem.replace(/\r$/, '').trim() && hParsed) processRow(parseLine(rem.replace(/\r$/, '').trim()));

  slowestArr.sort((a, b) => parseFloat(b.rt) - parseFloat(a.rt));
  thinArr.sort((a, b) => a.word_count - b.word_count);

  return {
    totalRows, sumRT, sumWC,
    indexableCount, nonIndexableCount,
    speedBuckets, wcBuckets, depthBuckets,
    slowestPages: slowestArr.slice(0, 10),
    orphanPages:  orphanArr.slice(0, 25),
    thinPages:    thinArr.slice(0, 15),
    http1Count: h1, http2Count: h2,
  };
}

// ── Process internal_html.csv ─────────────────────────────────
const ihKey = Object.keys(binary).find(k => binary[k]?.fileName === 'internal_html.csv');
let iStats = {
  totalRows:0, sumRT:0, sumWC:0, indexableCount:0, nonIndexableCount:0,
  speedBuckets:{excellent:0,good:0,needs_work:0,slow:0,critical:0},
  wcBuckets:{empty:0,thin:0,medium:0,good:0,rich:0},
  depthBuckets:{d1:0,d2:0,d3:0,d4:0,d5plus:0},
  slowestPages:[], orphanPages:[], thinPages:[], http1Count:0, http2Count:0,
};
if (ihKey) {
  const buf = await this.helpers.getBinaryDataBuffer(0, ihKey);
  iStats = processInternalHTML(buf);
}

const totalInternal     = iStats.totalRows || 1;
const indexableCount    = iStats.indexableCount;
const nonIndexableCount = iStats.nonIndexableCount;
const speedBuckets      = iStats.speedBuckets;
const wcBuckets         = iStats.wcBuckets;
const depthBuckets      = iStats.depthBuckets;
const slowestPages      = iStats.slowestPages;
const thinContentPages  = iStats.thinPages;
const http1Count        = iStats.http1Count;
const http2Count        = iStats.http2Count;
const avgResponseTime   = totalInternal > 0 ? (iStats.sumRT / totalInternal).toFixed(3) : '0.000';
const avgWordCount      = totalInternal > 0 ? Math.round(iStats.sumWC / totalInternal) : 0;

// ── File loading config ───────────────────────────────────────
const SKIP_FILES = new Set(['all_inlinks.csv', 'all_anchor_text.csv']);
const CORE_FILES = new Set([
  'internal_html.csv', 'issues_overview_report.csv', 'crawl_overview.csv',
  'client_error_(4xx)_inlinks.csv', 'response_codes_redirection_(3xx).csv',
  'redirect_chains.csv', 'hreflang_all_issues.csv', 'page_titles_missing.csv',
  'page_titles_duplicate.csv', 'page_titles_over_60_characters.csv',
  'meta_description_missing.csv', 'meta_description_over_155_characters.csv',
  'h1_missing.csv', 'h1_duplicate.csv', 'h1_multiple.csv', 'h2_missing.csv',
  'images_missing_alt_text.csv', 'images_over_100_kb.csv', 'directives_noindex.csv',
  'canonicals_missing.csv', 'canonicals_multiple_conflicting.csv',
  'canonicals_nonindexable_canonical.csv', 'content_exact_duplicates.csv',
  'content_near_duplicates.csv', 'content_low_content_pages.csv',
  'security_http_urls.csv', 'security_mixed_content.csv',
  'response_codes_client_error_(4xx).csv', 'response_codes_server_error_(5xx).csv',
  'response_codes_blocked_by_robots_txt.csv', 'redirect_and_canonical_chains.csv',
  'page_titles_below_30_characters.csv', 'meta_description_duplicate.csv',
  'meta_description_below_70_characters.csv',
]);
const SIZE_SKIP_THRESHOLD = 30 * 1024 * 1024;
const SAMPLE_LIMITS = {
  'client_error_(4xx)_inlinks.csv':          25000,
  'response_codes_redirection_(3xx).csv':    25000,
};

const files = {};
for (const key of Object.keys(binary)) {
  const file = binary[key];
  if (!file?.fileName || file.fileName === 'internal_html.csv') continue;
  if (SKIP_FILES.has(file.fileName)) { files[file.fileName] = { headers:[], rows:[], totalRows:0, skipped:true }; continue; }
  const fileBytes = file.fileSize || 0;
  if (fileBytes > SIZE_SKIP_THRESHOLD && !CORE_FILES.has(file.fileName)) {
    files[file.fileName] = { headers:[], rows:[], totalRows:0, skipped:true, reason:`auto_skipped_${Math.round(fileBytes/1024/1024)}MB` };
    continue;
  }
  let buf;
  try { buf = await this.helpers.getBinaryDataBuffer(0, key); }
  catch (e) { files[file.fileName] = { headers:[], rows:[], totalRows:0, error:e.message }; continue; }
  files[file.fileName] = parseCSVFromBuffer(buf, SAMPLE_LIMITS[file.fileName] ?? 99999, false);
}

