  if (col1?.startsWith('http')) websiteUrl = col1;
  let currentSection = '';
  ovFile.rows.forEach(r => {
    const k = (r[col0] || '').trim(), v = (r[col1] || '').trim();
    if (k && v === '') { currentSection = k; }
    else if (k && v !== '') {
      ovMeta[k] = v;
      if (currentSection) ovMeta[`${currentSection}::${k}`] = v;
    }
    if (k === 'Site Crawled' && v.startsWith('http')) websiteUrl = v;
  });
}

function getDomain(url) {
  try   { return new URL(url).hostname.toLowerCase().replace(/^www\./, ''); }
