// ── Redirects ─────────────────────────────────────────────────
const redirectGroupMap  = {};
const SOCIAL_NOISE      = new Set(['facebook.com','twitter.com','x.com','instagram.com','linkedin.com','pinterest.com','youtube.com','tiktok.com','in.linkedin.com','uk.linkedin.com']);
const AFFILIATE_DOMAINS = new Set(['amzn.to','bit.ly','tinyurl.com','ow.ly','buff.ly','goo.gl','ift.tt','dlvr.it','tiny.cc','rb.gy','cutt.ly']);

function isTrailingSlashOnly(from, to) { return from.replace(/\/$/, '') === to.replace(/\/$/, ''); }

getRows('response_codes_redirection_(3xx).csv').forEach(r => {
  const from = r['Address'] || '', to = r['Redirect URL'] || r['Redirect URI'] || '', code = r['Status Code'] || '';
  const inlinks = safeInt(r['Inlinks']);
  if (!from || !to) return;
  const fromD = getDomain(from), toD = getDomain(to);
  if (AFFILIATE_DOMAINS.has(fromD)) return;
  if (SOCIAL_NOISE.has(fromD) && isTrailingSlashOnly(from, to)) return;

  const fromIsHttp = from.startsWith('http://'), toIsHttps = to.startsWith('https://');
  const fromNoWww  = !from.replace(/https?:\/\//, '').startsWith('www.');
  const toHasWww   = to.replace(/https?:\/\//, '').startsWith('www.');
  const sameDomain = fromD === toD || ('www.' + fromD) === toD || fromD === toD.replace(/^www\./, '');
  const isClientFrom = siteDomain && (fromD.includes(siteDomain) || siteDomain.includes(fromD));
  const isClientTo   = siteDomain && (toD.includes(siteDomain) || siteDomain.includes(toD));

  let groupKey, groupLabel, groupType;
  if (isClientFrom && isClientTo) {
    if (fromIsHttp && toIsHttps && fromNoWww && toHasWww && sameDomain) { groupKey='__http_nonwww__'; groupLabel='HTTP + non-www → HTTPS + www (infrastructure)'; groupType='infrastructure'; }
    else if (fromIsHttp && toIsHttps && sameDomain) { groupKey='__http_https__'; groupLabel='HTTP → HTTPS (infrastructure)'; groupType='infrastructure'; }
    else if (fromNoWww && toHasWww && sameDomain && !fromIsHttp) { groupKey='__nonwww_www__'; groupLabel='Non-www → www (infrastructure)'; groupType='infrastructure'; }
    else { groupKey=from; groupLabel=null; groupType='internal'; }
  } else if (!isClientFrom && !isClientTo) {
    if (SOCIAL_NOISE.has(fromD)) return;
    groupKey=from; groupLabel=null; groupType='external';
  } else { groupKey=from; groupLabel=null; groupType='external'; }

  if (!redirectGroupMap[groupKey]) redirectGroupMap[groupKey] = { type:groupType, label:groupLabel||from, redirect_to:to, code, count:0, total_inlinks:0, examples:[] };
  redirectGroupMap[groupKey].count++;
  redirectGroupMap[groupKey].total_inlinks += inlinks;
  if (redirectGroupMap[groupKey].examples.length < 3) redirectGroupMap[groupKey].examples.push({ from, to, inlinks, code });
});

const sortOrder     = { infrastructure:0, internal:1, external:2 };
const allRedirectGroups = Object.values(redirectGroupMap).sort((a, b) => (sortOrder[a.type]??9)-(sortOrder[b.type]??9) || b.total_inlinks-a.total_inlinks);
