// ── Health score ─────────────────────────────────────────────
// CRITICAL: 4xx for health score = INTERNAL ONLY
// External 4xx = links to other broken sites — client can update links but not fix those servers
// Internal 4xx = your own site returning errors — directly your responsibility
// Score denominator = total internal HTML pages crawled (from internal_html.csv)
const healthDenominator = totalInternal || 1;

const criticalCount =
  internalOnly4xxCount +                                        // INTERNAL 4xx only (13 for spacem12, not 213)
  getCount('response_codes_server_error_(5xx).csv') +
  getCount('h1_missing.csv') +
  getCount('page_titles_missing.csv') +
  getCount('security_http_urls.csv') +
