  getCount('h1_multiple.csv') +
  getCount('images_missing_alt_text.csv') +
  getCount('content_low_content_pages.csv') +
  noindexCount +
  internalRedirectCount +
  getCount('images_over_100_kb.csv');

const criticalDeduction = Math.min(50, Math.round((criticalCount / healthDenominator) * 60));
const warningDeduction  = Math.min(30, Math.round((warningCount  / healthDenominator) * 25));
const healthScore       = Math.max(0, Math.min(100, 100 - criticalDeduction - warningDeduction));
const healthLabel       = healthScore >= 80 ? 'Good' : healthScore >= 60 ? 'Needs Work' : healthScore >= 40 ? 'Poor' : 'Critical';

