// ── SYSTEM PAGE DETECTOR ─────────────────────────────────────
function isSystemPage(url) {
  if (!url) return false;
  const u = url.toLowerCase();
  if (u.includes('/search?'))            return true;
  if (u.includes('/search/label/'))      return true;
  if (u.includes('/share-widget'))       return true;
  if (u.includes('?updated-max='))       return true;
  if (u.includes('?max-results='))       return true;
  if (u.includes('?reverse-paginate='))  return true;
  if (/\/search$/.test(u))               return true;
  if (/\/tag\/[^/]/.test(u))             return true;
  if (/\/category\/[^/]/.test(u))        return true;
  if (/\/author\/[^/]/.test(u))          return true;
  if (/\/page\/\d/.test(u))              return true;
  if (u.includes('/feed/'))              return true;
  if (u.includes('?feed='))              return true;
  if (/[?&]start=\d/.test(u))            return true;
  if (/[?&]paged=\d/.test(u))            return true;
  if (/[?&]page=\d/.test(u))             return true;
  if (u.includes('/wp-admin'))            return true;
  if (u.includes('/wp-login'))            return true;
  if (u.includes('/wp-json'))             return true;
  if (u.includes('/xmlrpc'))             return true;
  return false;
}

