// ── CSV PARSER ────────────────────────────────────────────────
function parseCSVFromBuffer(buffer) {
  const CHUNK = 65536;
  const headers = [], rows = [];
  let hParsed = false, rem = '';
  let start = 0;
  if (buffer.length >= 3 && buffer[0] === 0xEF && buffer[1] === 0xBB && buffer[2] === 0xBF) start = 3;

  function parseLine(line) {
    const result = [];
    let cur = '', inQ = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (c === '"') {
        if (inQ && line[i + 1] === '"') { cur += '"'; i++; }
        else inQ = !inQ;
      } else if (c === ',' && !inQ) { result.push(cur.trim()); cur = ''; }
      else { cur += c; }
    }
    result.push(cur.trim());
    return result;
  }

  for (let off = start; off < buffer.length; off += CHUNK) {
    const chunk    = buffer.slice(off, Math.min(off + CHUNK, buffer.length)).toString('utf-8');
    const combined = rem + chunk;
    const nli      = combined.lastIndexOf('\n');
    if (nli === -1) { rem = combined; continue; }
    const lines = combined.substring(0, nli + 1).split('\n');
    rem = combined.substring(nli + 1);
    for (const raw of lines) {
      const line = raw.replace(/\r$/, '').trim();
      if (!line) continue;
      if (!hParsed) { parseLine(line).forEach(h => headers.push(h.replace(/^\uFEFF/, ''))); hParsed = true; }
      else { const vals = parseLine(line); const obj = {}; headers.forEach((h, i) => { obj[h] = (vals[i] ?? '').trim(); }); rows.push(obj); }
    }
  }
  if (rem.trim() && hParsed) {
    const vals = parseLine(rem.trim()); const obj = {};
    headers.forEach((h, i) => { obj[h] = (vals[i] ?? '').trim(); }); rows.push(obj);
  }
  return { headers, rows, totalRows: rows.length };
}

// ── LOAD ALL FILES ────────────────────────────────────────────
const files = {};
for (const key of Object.keys(binary)) {
  const file = binary[key];
  if (!file?.fileName) continue;
  if (SKIP_FILES.has(file.fileName)) { files[file.fileName] = { headers:[], rows:[], totalRows:0, skipped:true }; continue; }
  let buf;
  try { buf = await this.helpers.getBinaryDataBuffer(0, key); }
  catch (e) { files[file.fileName] = { headers:[], rows:[], totalRows:0, error:e.message }; continue; }
  files[file.fileName] = parseCSVFromBuffer(buf);
}

const getFile   = n => files[n] || { headers:[], rows:[], totalRows:0 };
const allRows   = n => getFile(n).rows;
const getCount  = n => getFile(n).totalRows;
const safeInt   = v => { const n = parseInt(v || '0'); return isNaN(n) ? 0 : n; };
