const ovFile = getFile('crawl_overview.csv');
const ovMeta = {};
let websiteUrl = '';
let currentSection = '';

if (ovFile.headers?.length >= 2) {
  const col0 = ovFile.headers[0], col1 = ovFile.headers[1];
  if (col1?.startsWith('http')) websiteUrl = col1;
  ovFile.rows.forEach(r => {
    const k = (r[col0] || '').trim(), v = (r[col1] || '').trim();
    if (k && v === '') { currentSection = k; }
    else if (k && v !== '') {
      ovMeta[k] = v;
      if (currentSection) ovMeta[`${currentSection}::${k}`] = v;
    }
    if (k === 'Site Crawled' && v.startsWith('http')) websiteUrl = v;
  });
}

function getDomain(url) {
  try   { return new URL(url).hostname.toLowerCase().replace(/^www\./, ''); }
  catch { return (url || '').replace(/https?:\/\//, '').split('/')[0].toLowerCase().replace(/^www\./, ''); }
}
const siteDomain = websiteUrl ? getDomain(websiteUrl) : '';

const ov = (section, key) => {
  if (section && ovMeta[`${section}::${key}`] !== undefined) return parseInt(ovMeta[`${section}::${key}`])||0;
  return parseInt(ovMeta[key] || '0')||0;
};

// ── BROKEN LINKS — FULL 403 SPLIT ────────────────────────────
// Group all 4xx inlinks by destination URL
const brokenMap = {};
allRows('client_error_(4xx)_inlinks.csv').forEach(r => {
  const dest   = r['Destination'] || '';
  const src    = r['Source']      || '';
  const code   = r['Status Code'] || '';
  const anchor = r['Anchor']      || '';
  if (!dest || dest.includes('cdn-cgi')) return;

  if (!brokenMap[dest]) {
    const destDomain = getDomain(dest);
    const isInternal = siteDomain && (destDomain === siteDomain || destDomain.endsWith('.' + siteDomain));
    brokenMap[dest] = {
      broken_url:   dest,
      status_code:  code,
      anchor_text:  anchor,
      source_pages: [],
      total_inlinks: 0,
      issue_type:   isInternal ? 'Internal' : 'External',
      domain:       destDomain,
    };
  }
  brokenMap[dest].total_inlinks++;
  if (src && !brokenMap[dest].source_pages.includes(src)) brokenMap[dest].source_pages.push(src);
});

const REAL_BROKEN = new Set(['404', '410', '400']);
const BOT_CODES   = new Set(['403', '429', '401', '999']);

// ALL 404/410/400 unique broken URLs (internal + external)
