    h1_duplicate: { count: realCount('h1_duplicate.csv'), grouped: Object.values(h1TextMap).sort((a, b) => b.urls.length - a.urls.length).map(g => ({ h1: g.h1, page_count: g.urls.length, all_urls: g.urls })) },
