    h2_missing:   { count: realCount('h2_missing.csv'),   rows: realRows('h2_missing.csv').map(r => ({ url: r['Address'] || '' })) },
  },

  response_codes: {
    // 4xx rows from response_codes file (for the response codes tab)
    errors_4xx:     { count: realCount('response_codes_client_error_(4xx).csv'), rows: realRows('response_codes_client_error_(4xx).csv').map(r => ({ url: r['Address'] || '', code: r['Status Code'] || '', status: r['Status'] || '', inlinks: safeInt(r['Inlinks']) })).sort((a, b) => b.inlinks - a.inlinks) },
    errors_5xx:     { count: realCount('response_codes_server_error_(5xx).csv'), rows: realRows('response_codes_server_error_(5xx).csv').map(r => ({ url: r['Address'] || '', code: r['Status Code'] || '', status: r['Status'] || '', inlinks: safeInt(r['Inlinks']) })) },
    redirects_3xx:  { count: internalRedirectRows.length, rows: internalRedirectRows },
    blocked_robots: { count: getCount('response_codes_blocked_by_robots_txt.csv'), rows: allRows('response_codes_blocked_by_robots_txt.csv').map(r => ({ url: r['Address'] || '', robots_line: r['Matched Robots.txt Line'] || '' })) },
  },

  redirect_reports: {
    chains: {
      count: getCount('redirect_chains.csv'),
      rows: allRows('redirect_chains.csv').map(r => ({
        source: r['Source'] || r['Address'] || Object.values(r)[0] || '',
        final:  r['Final Address'] || r['Final URL'] || '',
        hops:   safeInt(r['Number of Redirects'] || r['Hops'] || '2'),
      }))
    },
  },

  images: {
    missing_alt: { count: realCount('images_missing_alt_text.csv'), rows: realRows('images_missing_alt_text.csv').map(r => ({ url: r['Address'] || '', size_kb: Math.round(safeInt(r['Size (bytes)']) / 1024), inlinks: safeInt(r['IMG Inlinks']) })) },
    oversized:   { count: realCount('images_over_100_kb.csv'),      rows: realRows('images_over_100_kb.csv').map(r => ({ url: r['Address'] || '', size_kb: Math.round(safeInt(r['Size (bytes)']) / 1024), inlinks: safeInt(r['IMG Inlinks']) })).sort((a, b) => b.size_kb - a.size_kb) },
  },

  canonicals: {
    missing:              { count: canonicalMissingFull.length, rows: canonicalMissingFull },
    multiple_conflicting: { count: realCount('canonicals_multiple_conflicting.csv'), rows: realRows('canonicals_multiple_conflicting.csv').map(r => ({ url: r['Address'] || '' })) },
    non_indexable:        { count: realCount('canonicals_nonindexable_canonical.csv'), rows: realRows('canonicals_nonindexable_canonical.csv').map(r => ({ url: r['Address'] || '' })) },
  },

  directives: {
    noindex: { count: noindexFull.length, rows: noindexFull },
  },

  content: {
    exact_duplicates: { count: realCount('content_exact_duplicates.csv'), rows: realRows('content_exact_duplicates.csv').map(r => ({ url: r['Address'] || '', hash: r['Hash'] || '' })) },
    near_duplicates:  { count: realCount('content_near_duplicates.csv'),  rows: realRows('content_near_duplicates.csv').map(r => ({ url: r['Address'] || '', similarity: r['Closest Similarity Match'] || '' })) },
    low_content:      { count: realCount('content_low_content_pages.csv'), rows: realRows('content_low_content_pages.csv').map(r => ({ url: r['Address'] || '', word_count: safeInt(r['Word Count']) })).sort((a, b) => a.word_count - b.word_count) },
  },

  security: {
    http_pages:    { count: realCount('security_http_urls.csv'),    rows: realRows('security_http_urls.csv').map(r => ({ url: r['Address'] || '', status_code: r['Status Code'] || '' })) },
    mixed_content: { count: getCount('security_mixed_content.csv'), rows: allRows('security_mixed_content.csv').map(r => ({ url: r['Address'] || '' })) },
  },

  // ── 4xx BROKEN LINK DATA (all categories) ──
  broken_link_sources:   broken_link_sources,  // ALL 404/410/400 URLs with issue_type
  broken404Count:        broken404Count,        // Unique 404-type URLs (for display counts)
  internal_403_links:    internal_403_links,    // Your own site returning 403 (WAF/CF)
  bot_blocked_links:     bot_blocked_links,     // Famous platforms blocking crawlers
  bot_blocked_count:     bot_blocked_count,     // Count of famous-domain 403s
  manual_check_links:    manual_check_links,    // Unknown external 403s — need manual check

  system_pages: {
    total_found:    totalSystemPages,
    by_type:        Object.entries(systemTypeMap).sort((a, b) => b[1] - a[1]).map(([type, count]) => ({ type, count })),
    recommendation: totalSystemPages > 0
      ? `${totalSystemPages} system-generated pages detected. Add noindex meta tags or robots.txt Disallow rules for these URL patterns to improve crawl budget.`
      : null,
  },
};

return [{ json: fullAudit }];

// ================================================================
// TAB BUILDER — Production v3.0
// Node name in n8n: "Tab Builder"
// Input:  Full Data Parser output
// Output: sheetData object → Excel File Builder
//
// TABS PRODUCED (only if data exists):
//  1.  Summary              — overview of all issues with counts + status
//  2.  Broken Pages (404)   — all 404/410 URLs (internal + external) with type badge
//  3.  Internal 403         — your own site pages blocking the crawler (WAF/CF)
//  4.  Check These 403      — unknown external 403s (need browser verification)
//  5.  Bot-Blocked 403      — famous platforms blocking crawlers (info only)
//  6.  Server Errors (5xx)  — server crash URLs
//  7.  HTTP Insecure         — HTTP pages needing HTTPS redirect
//  8.  Page Titles           — missing, too long, too short, duplicate
//  9.  Meta Descriptions     — missing, too long, too short
//  10. H1 and Headings       — missing, duplicate, multiple, missing H2
//  11. Images                — missing alt, oversized
//  12. Redirects (Internal)  — internal 3xx + redirect chains
//  13. Canonicals            — missing, conflicting, non-indexable
//  14. Indexation Issues     — noindex, thin content, near-duplicates
//  15. Exact Duplicates      — exact duplicate pages
//  16. Security              — HTTP + mixed content
//  17. Robots Blocked        — pages blocked by robots.txt
//  18. System Pages          — CMS auto-generated pages (excluded from other tabs)
// ================================================================

const audit  = $input.first().json;
const domain = (audit.meta.website || '').replace(/https?:\/\//, '').replace(/\/$/, '');
const date   = audit.meta.crawl_date || new Date().toISOString().split('T')[0];

// Clean cell value — no newlines, no tabs, max 1000 chars
const clean = v => String(v ?? '').replace(/[\r\n]+/g, ' ').replace(/\t/g, ' ').trim().substring(0, 1000);

function makeTab(name, headers, rows) {
  if (!rows || rows.length === 0) return null;
  return { name, headers, rows };
}

const tabs = [];

// ================================================================
// TAB 1: SUMMARY
// ================================================================
const internal403Count = audit.internal_403_links?.length || 0;
const manualCheck403   = audit.manual_check_links?.length || 0;
const botBlocked403    = audit.bot_blocked_count || 0;
const broken404Count   = audit.broken404Count || audit.broken_link_sources?.length || 0;

tabs.push({
  name: 'Summary',
  headers: ['METRIC', 'COUNT', 'STATUS', 'NOTES'],
  rows: [
    ['Website',              domain,                     '',   ''],
    ['Audit Date',           date,                       '',   ''],
    ['Total URLs Crawled',   audit.meta.co_total_crawled || audit.meta.total_urls_crawled || 0, '', ''],
    ['Indexable Pages',      audit.meta.co_indexable     || 0, '', 'From Screaming Frog crawl overview'],
    ['Non-Indexable',        audit.meta.co_non_indexable || 0, '', 'Blocked from Google'],
    ['Internal URLs',        audit.meta.co_internal_all  || 0, '', 'All internal URL types'],
    ['External URLs',        audit.meta.co_external_all  || 0, '', 'External links crawled'],
    ['System Pages Excluded',audit.meta.system_pages_found || 0, '', 'See System Pages tab'],
    ['', '', '', ''],

    ['── CRITICAL ISSUES ──────────────────────────────', '', '', ''],
    ['Broken Pages (404/410)',          broken404Count,                              broken404Count > 0           ? 'CRITICAL' : 'OK', 'See Broken Pages tab — 301 redirect or remove links'],
    ['Internal 403 Errors (Your Site)', internal403Count,                            internal403Count > 0         ? 'CRITICAL' : 'OK', 'See Internal 403 tab — WAF/Cloudflare blocking crawler'],
    ['Server Errors (5xx)',             audit.response_codes?.errors_5xx?.count || 0, (audit.response_codes?.errors_5xx?.count || 0) > 0 ? 'CRITICAL' : 'OK', 'Check server/plugin logs immediately'],
    ['Missing H1 Headings',             audit.headings?.h1_missing?.count || 0,       (audit.headings?.h1_missing?.count || 0) > 0 ? 'CRITICAL' : 'OK', 'Add H1 to every content page'],
    ['Missing Page Titles',             audit.page_titles?.missing?.count || 0,        (audit.page_titles?.missing?.count || 0) > 0 ? 'CRITICAL' : 'OK', 'Add unique 50–60 char title'],
    ['HTTP Insecure Pages',             audit.security?.http_pages?.count || 0,        (audit.security?.http_pages?.count || 0) > 0 ? 'CRITICAL' : 'OK', '301 redirect all HTTP pages to HTTPS'],
    ['Exact Duplicate Pages',           audit.content?.exact_duplicates?.count || 0,   (audit.content?.exact_duplicates?.count || 0) > 0 ? 'CRITICAL' : 'OK', 'Add canonical or 301 redirect'],
    ['', '', '', ''],

    ['── WARNING ISSUES ───────────────────────────────', '', '', ''],
    ['External 403 (Check These)',       manualCheck403,                               manualCheck403 > 0       ? 'Check Manually' : 'OK', 'See Check These 403 tab — open each in browser'],
    ['Missing Meta Descriptions',        audit.meta_descriptions?.missing?.count || 0,  (audit.meta_descriptions?.missing?.count || 0) > 0 ? 'Fix Soon' : 'OK', '140–155 chars with keyword + CTA'],
    ['Page Titles Too Long (>60)',        audit.page_titles?.too_long?.count || 0,       (audit.page_titles?.too_long?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Shorten to under 60 chars'],
    ['Duplicate H1 Headings',            audit.headings?.h1_duplicate?.count || 0,      (audit.headings?.h1_duplicate?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Each page needs unique H1'],
    ['Multiple H1 on Same Page',         audit.headings?.h1_multiple?.count || 0,       (audit.headings?.h1_multiple?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Usually a template fix'],
    ['Images Missing Alt Text',          audit.images?.missing_alt?.count || 0,         (audit.images?.missing_alt?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Add descriptive alt attribute'],
    ['Oversized Images (>100KB)',         audit.images?.oversized?.count || 0,           (audit.images?.oversized?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Compress and convert to WebP'],
    ['Redirect Chains',                  audit.redirect_reports?.chains?.count || 0,    (audit.redirect_reports?.chains?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Update links to final URL'],
    ['Internal Redirects',               audit.response_codes?.redirects_3xx?.count || 0, (audit.response_codes?.redirects_3xx?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Update internal links to skip redirect'],
    ['Missing Canonical Tags',           audit.canonicals?.missing?.count || 0,         (audit.canonicals?.missing?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Add self-referencing canonical'],
    ['Thin Content (<300 words)',         audit.content?.low_content?.count || 0,        (audit.content?.low_content?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Expand or consolidate pages'],
    ['Near-Duplicate Pages',             audit.content?.near_duplicates?.count || 0,    (audit.content?.near_duplicates?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Differentiate or canonicalise'],
    ['Mixed Content (HTTP on HTTPS)',     audit.security?.mixed_content?.count || 0,     (audit.security?.mixed_content?.count || 0) > 0 ? 'Fix Soon' : 'OK', 'Update HTTP resource URLs to HTTPS'],
    ['', '', '', ''],

    ['── INFO ONLY ────────────────────────────────────', '', '', ''],
    ['Known Bot-Blocking Platforms (403)', botBlocked403, 'No Action', 'Famous sites (Twitter, Wikipedia etc.) that block crawlers — links work in browser'],
    ['Internal 4xx Total (SF)',             audit.meta.co_internal_4xx || 0, 'Reference', 'From Screaming Frog crawl overview — all 4xx on your server'],
    ['External 4xx Total (SF)',             audit.meta.co_external_4xx || 0, 'Reference', 'From Screaming Frog — external URLs you link to that are broken'],
    ['External Redirects Total (SF)',       audit.meta.co_external_3xx || 0, 'Reference', 'External URLs you link to that redirect — not your issue to fix'],
    ['', '', '', ''],

    ['── HOW TO USE THIS FILE ─────────────────────────', '', '', ''],
    ['Status Column',    'Change TODO → IN PROGRESS or DONE as you fix each URL', '', ''],
    ['System Pages',     'See the System Pages tab for CMS auto-generated pages info', '', ''],
    ['PDF Report',       'See the PDF report for full analysis, priorities, and explanations', '', ''],
    ['Priority Order',   'Fix CRITICAL first, then Fix Soon, then Info Only', '', ''],
  ]
});

// ================================================================
// TAB 2: BROKEN PAGES (404/410/400) — Internal + External
// ================================================================
const brokenRows = (audit.broken_link_sources || []).map((r, i) => [
  i + 1,
  r.issue_type === 'Internal 404' ? 'INTERNAL' : 'EXTERNAL',
  clean(r.broken_url),
  r.status_code || '404',
  r.total_inlinks || 0,
  clean((r.source_pages || []).slice(0, 5).join(' | ')),
  r.issue_type === 'Internal 404'
    ? '301 redirect to nearest live page OR remove all internal links pointing to this URL'
    : 'Update your link to point to a working alternative URL on that site',
  'TODO'
]);
const t2 = makeTab('Broken Pages (404)', ['#', 'Type', 'Broken URL', 'Code', 'Inlinks', 'Pages Linking To It', 'Fix Action', 'Status'], brokenRows);
if (t2) tabs.push(t2);

// ================================================================
// TAB 3: INTERNAL 403 — Your own site blocking crawler
// ================================================================
const int403Rows = (audit.internal_403_links || []).map((r, i) => [
  i + 1,
  clean(r.broken_url),
  r.status_code || '403',
  r.total_inlinks || 0,
  clean((r.source_pages || []).slice(0, 3).join(' | ')),
  'Check Cloudflare/WAF Bot Management — if Googlebot is also blocked, these pages cannot be indexed',
  'TODO'
]);
const t3 = makeTab('Internal 403 (YOUR Site)', ['#', 'Your Page (Blocked)', 'Code', 'Inlinks', 'Linked From', 'Fix Action', 'Status'], int403Rows);
if (t3) tabs.push(t3);

// ================================================================
// TAB 4: MANUAL CHECK 403 — Unknown external 403s
// ================================================================
const manualCheckRows = (audit.manual_check_links || []).map((r, i) => [
  i + 1,
  clean(r.broken_url),
  r.status_code || '403',
  r.total_inlinks || 0,
  clean((r.source_pages || []).slice(0, 2).join(' | ')),
  'Open URL in browser (Incognito). If it loads = bot-blocking only, link is fine. If 403 in browser too = link is broken, fix it.',
  'TODO'
]);
const t4 = makeTab('Check These 403', ['#', 'External URL', 'Code', 'Inlinks', 'Linked From', 'Action Required', 'Status'], manualCheckRows);
if (t4) tabs.push(t4);

// ================================================================
// TAB 5: BOT-BLOCKED 403 — Famous platforms (info only, no fixes)
// ================================================================
const botBlockedRows = (audit.bot_blocked_links || []).map((r, i) => [
  i + 1,
  clean(r.broken_url),
  r.domain || '',
  r.status_code || '403',
  r.total_inlinks || 0,
  'No action needed — this platform blocks all automated crawlers. Link works fine in a browser.'
