// ================================================================
// TAB 6: SERVER ERRORS (5xx)
// ================================================================
const e5xxRows = (audit.response_codes?.errors_5xx?.rows || []).map((r, i) => [
  i + 1, clean(r.url), r.code || '5xx', r.status || '', r.inlinks || 0,
  'Check server error logs immediately — likely PHP memory, database, or plugin failure', 'TODO'
]);
const t6 = makeTab('Server Errors (5xx)', ['#', 'URL', 'Code', 'Status', 'Inlinks', 'Fix Action', 'Status'], e5xxRows);
if (t6) tabs.push(t6);

// ================================================================
// TAB 7: HTTP INSECURE PAGES
// ================================================================
const httpRows = (audit.security?.http_pages?.rows || []).map((r, i) => [
  i + 1, clean(r.url), r.status_code || '', '301 redirect to HTTPS version and verify SSL certificate covers all subdomains', 'TODO'
]);
const t7 = makeTab('HTTP Insecure', ['#', 'URL', 'Status Code', 'Fix Action', 'Status'], httpRows);
