const titleRows = [];
let ti = 1;
(audit.page_titles?.missing?.rows || []).forEach(r => {
  titleRows.push([ti++, clean(r.url), '(missing)', 0, 'Missing', 'Add unique 50–60 char title with primary keyword near the start', 'TODO']);
});
(audit.page_titles?.too_long?.rows || []).forEach(r => {
  titleRows.push([ti++, clean(r.url), clean(r.title), r.length || '?', 'Too Long (>60)', 'Shorten to under 60 chars — keep keyword within first 50', 'TODO']);
});
(audit.page_titles?.too_short?.rows || []).forEach(r => {
  titleRows.push([ti++, clean(r.url), '(short title)', '', 'Too Short (<30)', 'Expand title to 40–60 chars with primary keyword and brand name', 'TODO']);
});
(audit.page_titles?.duplicate?.grouped || []).forEach(g => {
  (g.all_urls || []).forEach(url => {
    titleRows.push([ti++, clean(url), clean(g.title), '', 'Duplicate', `Write unique title — current shared: "${clean(g.title).substring(0, 50)}"`, 'TODO']);
  });
});
const t8 = makeTab('Page Titles', ['#', 'URL', 'Current Title', 'Length', 'Issue', 'Fix Action', 'Status'], titleRows);
if (t8) tabs.push(t8);

// ================================================================
// TAB 9: META DESCRIPTIONS
// ================================================================
const metaRows = [];
let mi = 1;
(audit.meta_descriptions?.missing?.rows || []).forEach(r => {
  metaRows.push([mi++, clean(r.url), '(missing)', 0, 'Missing', 'Write 140–155 char description with keyword and clear CTA', 'TODO']);
});
(audit.meta_descriptions?.too_long?.rows || []).forEach(r => {
  metaRows.push([mi++, clean(r.url), clean(r.meta), r.length || '?', 'Too Long (>155)', 'Trim to under 155 chars — keep CTA within first 140', 'TODO']);
});
(audit.meta_descriptions?.too_short?.rows || []).forEach(r => {
  metaRows.push([mi++, clean(r.url), '(short meta)', '', 'Too Short (<70)', 'Expand to 140–155 chars with keyword and CTA', 'TODO']);
});
const t9 = makeTab('Meta Descriptions', ['#', 'URL', 'Current Meta', 'Length', 'Issue', 'Fix Action', 'Status'], metaRows);
if (t9) tabs.push(t9);

// ================================================================
// TAB 10: H1 AND HEADINGS
// ================================================================
const h1Rows = [];
let hi = 1;
(audit.headings?.h1_missing?.rows || []).forEach(r => {
  h1Rows.push([hi++, clean(r.url), '(missing)', 'Missing H1', 'Add exactly one H1 describing page topic — include primary keyword', 'TODO']);
});
(audit.headings?.h1_duplicate?.grouped || []).forEach(g => {
  (g.all_urls || []).forEach(url => {
    h1Rows.push([hi++, clean(url), clean(g.h1), 'Duplicate H1', `Write unique H1 — current shared: "${clean(g.h1).substring(0, 50)}"`, 'TODO']);
  });
});
(audit.headings?.h1_multiple?.rows || []).forEach(r => {
  h1Rows.push([hi++, clean(r.url), clean(r.h1_second), 'Multiple H1s on Page', `Remove or change to H2: "${clean(r.h1_second).substring(0, 50)}" — usually a template fix`, 'TODO']);
});
(audit.headings?.h2_missing?.rows || []).forEach(r => {
  h1Rows.push([hi++, clean(r.url), '(missing)', 'Missing H2', 'Add H2 subheadings to divide content into logical sections', 'TODO']);
});
const t10 = makeTab('H1 and Headings', ['#', 'URL', 'Heading Text', 'Issue Type', 'Fix Action', 'Status'], h1Rows);
