const imgRows = [];
let ii = 1;
(audit.images?.missing_alt?.rows || []).forEach(r => {
  imgRows.push([ii++, clean(r.url), r.size_kb || 0, r.inlinks || 0, 'Missing Alt Text', 'Add descriptive alt text explaining what image shows — use keyword where natural', 'TODO']);
