});
(audit.security?.mixed_content?.rows || []).forEach(r => {
  secRows.push([si2++, clean(r.url), '', 'Mixed Content', 'Update all HTTP resource URLs (images, scripts, CSS) on this page to HTTPS', 'TODO']);
});
const t16 = makeTab('Security', ['#', 'URL', 'Status Code', 'Issue', 'Fix Action', 'Status'], secRows);
if (t16) tabs.push(t16);

// ================================================================
// TAB 17: ROBOTS BLOCKED
// ================================================================
const robotRows = (audit.response_codes?.blocked_robots?.rows || []).map((r, i) => [
  i + 1, clean(r.url), clean(r.robots_line), 'Blocked by robots.txt',
  'If this page should be crawled by Google, update robots.txt to allow this URL pattern', 'TODO'
]);
const t17 = makeTab('Robots Blocked', ['#', 'URL', 'Robots.txt Rule', 'Issue', 'Fix Action', 'Status'], robotRows);
if (t17) tabs.push(t17);

// ================================================================
// TAB 18: SYSTEM PAGES
// ================================================================
const sp = audit.system_pages || {};
if (sp.total_found > 0) {
  const spRows = [];
  spRows.push(['OVERVIEW', '', '', '']);
  spRows.push([`${sp.total_found} system-generated pages were found during the crawl`, '', '', '']);
  spRows.push(['These are CMS auto-generated pages (label archives, paginated search, share widgets, feeds)', '', '', '']);
  spRows.push(['They cannot have custom H1/title tags and create duplicate content signals across your site', '', '', '']);
  spRows.push(['They have been EXCLUDED from all other tabs in this file — counts reflect real content pages only', '', '', '']);
  spRows.push(['', '', '', '']);
  spRows.push(['BREAKDOWN BY TYPE', '', '', '']);
  spRows.push(['Type', 'Count', 'Recommendation', '']);
  (sp.by_type || []).forEach(bt => {
    const rec = bt.type === 'Label/Tag Archive' ? 'Add noindex meta tag to all label/tag archive pages'
              : bt.type === 'Search Results'    ? 'Add noindex meta tag to all /search pages'
              : bt.type === 'Paginated Pages'   ? 'Add canonical pointing to base page, or noindex on paginated pages'
              : bt.type === 'Share Widget'      ? 'Block in robots.txt: Disallow: /share-widget'
              : bt.type === 'Feed / RSS'        ? 'Block in robots.txt: Disallow: /feed/'
              : bt.type === 'Category Archive'  ? 'Add noindex to category archives or ensure they have unique content'
              : bt.type === 'Tag Archive'       ? 'Add noindex to tag archives — they rarely rank'
              : 'Review and add noindex or robots.txt Disallow';
    spRows.push([bt.type, bt.count, rec, '']);
  });
  spRows.push(['', '', '', '']);
  spRows.push(['WHY THIS MATTERS', '', '', '']);
  spRows.push(['Crawl Budget', 'Google wastes crawl budget on these pages instead of your real content pages', '', '']);
  spRows.push(['Duplicate Content', 'These pages often have identical or near-identical content — dilutes SEO signals', '', '']);
  spRows.push(['False Metrics', 'They inflate issue counts in SEO tools — excluded here for accurate reporting', '', '']);
  spRows.push(['H1/Title Issues', 'System pages often have missing H1s/titles that cannot be fixed — excluded from those counts', '', '']);

  tabs.push({
    name: 'System Pages',
    headers: ['Detail', 'Value', 'Action', 'Notes'],
    rows: spRows,
  });
}

// ================================================================
// FINAL OUTPUT
// ================================================================
return [{
  json: {
    spreadsheet_title: `SEO Implementation Sheet — ${domain} — ${date}`,
    domain,
    date,
    total_tabs: tabs.length,
    tabs,
  }
}];

// ================================================================
// EXCEL FILE BUILDER — Production v2.0
// Node name in n8n: "Excel File Builder"
// Input:  Tab Builder output (sheetData with tabs array)
// Output: ONE .xls file (Excel XML Spreadsheet format)
//
// FEATURES:
//   - Dark navy header row with white bold text
//   - CRITICAL rows highlighted red in Summary tab
//   - INFO rows highlighted light grey in Summary tab
//   - Bot-blocked note rows styled differently
//   - Clean divider rows styled blue in Summary tab
//   - All cells forced as String (prevents formula injection)
//   - Compatible with Excel, LibreOffice, Google Sheets
// ================================================================

const sheetData = $input.first().json;
if (!sheetData || !sheetData.tabs || sheetData.tabs.length === 0) {
  throw new Error('No tab data received. Check Tab Builder node is connected and producing output.');
}

// ── COLOUR CONSTANTS ──────────────────────────────────────────
const COLOR = {
  HEADER_BG:    '#0A1628',  // Dark navy — header row
  HEADER_FG:    '#FFFFFF',  // White text
  DIVIDER_BG:   '#2563EB',  // Blue — section dividers in summary
  DIVIDER_FG:   '#FFFFFF',  // White text
  CRITICAL_BG:  '#FEE2E2',  // Light red — CRITICAL status rows
  CRITICAL_FG:  '#B91C1C',  // Dark red text
  WARNING_BG:   '#FFFBEB',  // Light amber — Check/Fix Soon rows
  WARNING_FG:   '#92400E',  // Amber text
  OK_BG:        '#ECFDF5',  // Light green — OK rows
  OK_FG:        '#065F46',  // Green text
  INFO_BG:      '#F8FAFC',  // Light grey — info-only rows
  INFO_FG:      '#475569',  // Grey text
  BOT_BG:       '#F1F5F9',  // Very light grey — bot-blocked rows
  BOT_FG:       '#64748B',  // Medium grey text
  ODD_ROW_BG:   '#FAFAFA',  // Alternate row shading (odd)
  DEFAULT_BG:   '#FFFFFF',  // Default white
};

// ── BUILD EXCEL XML ───────────────────────────────────────────
let xml = `<?xml version="1.0" encoding="UTF-8"?>
<?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:html="http://www.w3.org/TR/REC-html40">
  <Styles>
    <!-- Default cell style -->
    <Style ss:ID="Default" ss:Name="Normal">
      <Alignment ss:Vertical="Bottom" ss:WrapText="0"/>
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="#000000"/>
      <Interior/>
    </Style>
    <!-- Header row: dark navy background, white bold -->
    <Style ss:ID="Header">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.HEADER_FG}" ss:Bold="1"/>
      <Interior ss:Color="${COLOR.HEADER_BG}" ss:Pattern="Solid"/>
      <Alignment ss:Vertical="Center"/>
    </Style>
    <!-- Section divider: blue background, white bold (Summary tab) -->
    <Style ss:ID="Divider">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.DIVIDER_FG}" ss:Bold="1"/>
      <Interior ss:Color="${COLOR.DIVIDER_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- CRITICAL status rows: light red -->
    <Style ss:ID="Critical">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.CRITICAL_FG}" ss:Bold="1"/>
      <Interior ss:Color="${COLOR.CRITICAL_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- Warning / Fix Soon rows: light amber -->
    <Style ss:ID="Warning">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.WARNING_FG}"/>
      <Interior ss:Color="${COLOR.WARNING_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- OK rows: light green -->
    <Style ss:ID="OK">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.OK_FG}"/>
      <Interior ss:Color="${COLOR.OK_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- Info-only rows: light grey -->
    <Style ss:ID="Info">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.INFO_FG}"/>
      <Interior ss:Color="${COLOR.INFO_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- Bot-blocked rows: very light grey -->
    <Style ss:ID="BotBlocked">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="${COLOR.BOT_FG}" ss:Italic="1"/>
      <Interior ss:Color="${COLOR.BOT_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- Alternating row (odd rows slightly shaded) -->
    <Style ss:ID="OddRow">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="#000000"/>
      <Interior ss:Color="${COLOR.ODD_ROW_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- Plain white row -->
    <Style ss:ID="EvenRow">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="#000000"/>
      <Interior ss:Color="${COLOR.DEFAULT_BG}" ss:Pattern="Solid"/>
    </Style>
    <!-- TODO cell: neutral -->
    <Style ss:ID="TodoCell">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="#475569"/>
      <Interior ss:Color="#F1F5F9" ss:Pattern="Solid"/>
      <Alignment ss:Horizontal="Center"/>
    </Style>
    <!-- Number cells: right-aligned -->
    <Style ss:ID="NumCell">
      <Font ss:FontName="Calibri" ss:Size="11" ss:Color="#000000"/>
      <Alignment ss:Horizontal="Right"/>
    </Style>
    <!-- INTERNAL badge: red text -->
    <Style ss:ID="InternalBadge">
      <Font ss:FontName="Calibri" ss:Size="10" ss:Color="#B91C1C" ss:Bold="1"/>
      <Interior ss:Color="#FEE2E2" ss:Pattern="Solid"/>
      <Alignment ss:Horizontal="Center"/>
    </Style>
    <!-- EXTERNAL badge: amber text -->
    <Style ss:ID="ExternalBadge">
      <Font ss:FontName="Calibri" ss:Size="10" ss:Color="#92400E" ss:Bold="1"/>
      <Interior ss:Color="#FEF3C7" ss:Pattern="Solid"/>
      <Alignment ss:Horizontal="Center"/>
    </Style>
    <!-- NO ACTION badge: grey -->
    <Style ss:ID="NoAction">
      <Font ss:FontName="Calibri" ss:Size="10" ss:Color="#475569" ss:Italic="1"/>
      <Interior ss:Color="#F1F5F9" ss:Pattern="Solid"/>
      <Alignment ss:Horizontal="Center"/>
    </Style>
  </Styles>
`;

// ── HELPER: Escape XML special characters ─────────────────────
function esc(v) {
  return String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ''); // strip non-printable chars
}

// ── HELPER: Determine cell style ──────────────────────────────
function getCellStyle(tabName, colIndex, cellValue, rowIndex, allCells) {
  const isSummary = tabName === 'Summary';
  const cellStr   = String(cellValue ?? '');

  // ── Summary tab special styling ──────────────────────────────
  if (isSummary) {
    // Section divider rows (first column starts with ──)
    if (cellStr.startsWith('──')) return 'Divider';

    // Status column (col 2, index 2) in summary data rows
    if (colIndex === 2 && rowIndex > 0) {
      if (cellStr === 'CRITICAL')        return 'Critical';
      if (cellStr === 'Fix Soon')        return 'Warning';
      if (cellStr === 'Check Manually') return 'Warning';
      if (cellStr === 'OK')              return 'OK';
      if (cellStr === 'No Action')       return 'Info';
      if (cellStr === 'Reference')       return 'Info';
    }

    // Count column (col 1, index 1) — colour based on status in col 2
    if (colIndex === 1 && rowIndex > 0) {
      const statusCell = String(allCells[2] ?? '');
      if (statusCell === 'CRITICAL')        return 'Critical';
      if (statusCell === 'Fix Soon')        return 'Warning';
      if (statusCell === 'Check Manually') return 'Warning';
      if (statusCell === 'OK')              return 'OK';
      if (statusCell === 'No Action')       return 'Info';
      if (statusCell === 'Reference')       return 'Info';
    }
    return null; // default
  }

  // ── Issue tabs — Type/badge column ────────────────────────────
  if (tabName === 'Broken Pages (404)' && colIndex === 1) {
    if (cellStr === 'INTERNAL') return 'InternalBadge';
    if (cellStr === 'EXTERNAL') return 'ExternalBadge';
  }

  // ── Status column (last column of most tabs) ──────────────────
  const lastCol = (allCells.length - 1);
  if (colIndex === lastCol) {
    if (cellStr === 'TODO')                    return 'TodoCell';
    if (cellStr === 'No action needed — this platform blocks all automated crawlers. Link works fine in a browser.') return 'NoAction';
  }

  // ── Bot-blocked tab — entire row in grey ──────────────────────
  if (tabName === 'Bot-Blocked 403 (Info)') return 'BotBlocked';

  // ── Alternating row shading for data tabs ─────────────────────
  if (rowIndex > 0) {
    return rowIndex % 2 === 0 ? 'EvenRow' : 'OddRow';
  }

  return null;
}

// ── BUILD EACH WORKSHEET ──────────────────────────────────────
for (const tab of sheetData.tabs) {
  if (!tab.rows || tab.rows.length === 0) continue;

  // Clean tab name: max 31 chars, no forbidden characters
  const cleanName = tab.name
    .replace(/[[\]*\/:\\?]/g, '')
    .substring(0, 31)
    .trim();

  // For Summary: rows already include headers in the row data
  // For others: first row = headers, then data rows
  const isSummary = tab.name === 'Summary';
  const allRowData = isSummary
    ? tab.rows
    : [tab.headers, ...tab.rows];

  xml += `\n  <Worksheet ss:Name="${esc(cleanName)}">`;
  xml += `\n    <Table ss:DefaultColumnWidth="120">`;

  for (let rIdx = 0; rIdx < allRowData.length; rIdx++) {
    const row = allRowData[rIdx];
    if (!Array.isArray(row)) continue;

    // Determine if this is the header row (first row of non-summary tabs)
    const isHeaderRow = !isSummary && rIdx === 0;

    xml += `\n      <Row${isHeaderRow ? ' ss:Height="22"' : ''}>`;

    for (let cIdx = 0; cIdx < row.length; cIdx++) {
      const cellVal = row[cIdx];
      const cellStr = String(cellVal ?? '');

      // Style decision
      let styleID = null;
      if (isHeaderRow) {
        styleID = 'Header';
      } else {
        styleID = getCellStyle(tab.name, cIdx, cellStr, rIdx, row);
      }

      const styleAttr = styleID ? ` ss:StyleID="${styleID}"` : '';

      // Force all cells as String to prevent Excel misinterpreting URLs, numbers, dates
      xml += `\n        <Cell${styleAttr}><Data ss:Type="String">${esc(cellStr)}</Data></Cell>`;
    }

    xml += `\n      </Row>`;
  }

  xml += `\n    </Table>`;
  xml += `\n  </Worksheet>`;
}

xml += `\n</Workbook>`;

// ── PRODUCE OUTPUT FILE ───────────────────────────────────────
const cleanDomain = (sheetData.domain || 'report')
  .replace(/[^a-zA-Z0-9_\-]/g, '_')
  .substring(0, 40);
const filename = `${cleanDomain}_SEO_Issues_${sheetData.date || 'audit'}.xls`;

const buffer     = Buffer.from(xml, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, filename, 'application/vnd.ms-excel');

return [{
  json: {
    status:               'Success',
    filename:             filename,
    total_tabs_generated: sheetData.tabs.filter(t => t.rows?.length > 0).length,
    domain:               sheetData.domain,
    date:                 sheetData.date,
    spreadsheet_title:    sheetData.spreadsheet_title,
  },
  binary: {
    data: binaryData,
  }
}];

// Get the raw text from the previous node 
// (Make sure to map the correct input variable here if it's not called "text")
const incomingText = $input.item.json.text || "";

let cleanUrl = null;

// Regex to find an HTTP or HTTPS link, ignoring the < and > brackets Slack adds
const urlRegex = /https?:\/\/[^\s>]+/g;

// Search the text for the URL
const match = incomingText.match(urlRegex);

// If a URL was found in the text
if (match && match.length > 0) {
  cleanUrl = match[0];

  // Return the item with a new "extracted_url" field
  return { 
    json: { 
      ...$input.item.json, // Keep the original data just in case
      extracted_url: cleanUrl,
      isValid: true
    } 
  };
} else {
  // If no URL was found, return false so you can filter it out
  return { 
    json: { 
       ...$input.item.json,
      extracted_url: null,
      isValid: false
    } 
  };
}

// ================================================================
// SEO AUDIT REPORT BUILDER — Production v4.2
// Node name in n8n: "Report Builder"
// Input: merged audit+psi JSON from PSI Parser node
//
// FIXES IN v4.2:
//  - real4xxCount = broken404Count (404-only unique URLs, not all 4xx)
//  - Bot-blocked: count-only note, no table
//  - New: manual_check_403 table for unknown external 403s
//  - External redirect: shows true count (203) from crawl_overview
//  - Internal redirect: shows true count from crawl_overview
// ================================================================

const audit = $input.first().json;
const psi   = audit.psi || {};
const co    = audit.meta.crawl_overview || {};

// ── CRAWL OVERVIEW SHORTCUTS ──
const trueTotalCrawled = co.total_urls_crawled || audit.meta.total_urls_crawled || 0;
const trueIndexable    = co.internal?.indexable || audit.meta.indexable || 0;

// ── WATERMARK ──
const wm = $('Input Cleaner').first().json.watermark;

// ── BASE HELPERS ──
const safe = v => String(v||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const num  = v => { const n = parseInt(v||0); return isNaN(n)?'0':n.toLocaleString(); };
const pct  = (v,t) => t>0?Math.round((v/t)*100):0;
const domain = (audit.meta.website||'').replace(/https?:\/\//,'').replace(/\/$/,'');

// ── AGENCY CONFIG ── (change these to your agency details)
const AGENCY = {
  name:    'AuditCore',
  initial: 'AC',
  email:   '+1234567890',
  website: '',
  tagline: 'Technical SEO & Growth'
};

// ── HEALTH SCORE COLORS ──
const sc = audit.health.score;
const scoreColor = sc>=80?'#10B981':sc>=60?'#F59E0B':sc>=40?'#EF4444':'#B91C1C';

// ── CWV HELPERS ──
const cwvColor  = s => s==='good'?'#10B981':s==='needs_improvement'?'#F59E0B':'#EF4444';
const cwvBg     = s => s==='good'?'#ECFDF5':s==='needs_improvement'?'#FFFBEB':'#FEF2F2';
const cwvLabel  = s => s==='good'?'Good':s==='needs_improvement'?'Needs Improvement':'Poor';
const cwvBorder = s => s==='good'?'#A7F3D0':s==='needs_improvement'?'#FDE68A':'#FECACA';

// ── SCREAMING FROG SPEED ──
const avgRT      = parseFloat(audit.meta.avg_response_time||0);
const avgRTLabel = avgRT<0.2?'Excellent':avgRT<0.5?'Good':avgRT<1.0?'Needs Attention':avgRT<2.0?'Slow':'Critical';
const avgRTColor = avgRT<0.5?'#10B981':avgRT<1.0?'#F59E0B':'#EF4444';

// ── 4xx COUNTS ──
// real4xxCount = unique 404/410/400 URLs only (what shows in headings + priority action + cover)
const real4xxCount = audit.response_codes?.errors_4xx?.real_count ?? audit.response_codes?.errors_4xx?.broken_404 ?? audit.broken_link_sources?.length ?? 0;

// ── PERF SCORE ──
const perfScore = psi.performance_score || 0;
const perfColor = perfScore>=90?'#10B981':perfScore>=50?'#F59E0B':'#EF4444';
const perfLabel = perfScore>=90?'Good':perfScore>=50?'Needs Improvement':'Poor';

// ── TOP 3 PRIORITY ACTIONS ──
const SEV = { critical:1000, warning:10, low:1 };
const psiLcpPoor = psi.lcp?.status === 'poor';
const priorityCandidates = [
  { w: SEV.critical+(real4xxCount*10),                               t:`Fix ${num(real4xxCount)} broken pages (404 errors) — each wastes crawl budget and destroys link equity` },
  { w: SEV.critical+(audit.response_codes?.errors_5xx?.count||0)*10, t:`Resolve ${num(audit.response_codes?.errors_5xx?.count)} server errors (5xx) — Google may stop crawling affected pages` },
  { w: SEV.critical+(audit.headings?.h1_missing?.count||0)*8,        t:`Add H1 headings to ${num(audit.headings?.h1_missing?.count)} pages — missing the strongest on-page ranking signal` },
  { w: SEV.critical+(audit.page_titles?.missing?.count||0)*8,        t:`Add missing page titles to ${num(audit.page_titles?.missing?.count)} pages — zero title-based ranking signal` },
  { w: SEV.critical+(audit.security?.http_pages?.count||0)*8,        t:`Fix ${num(audit.security?.http_pages?.count)} HTTP insecure pages — ranking penalty and browser warning` },
  { w: SEV.critical+(audit.content?.exact_duplicates?.count||0)*8,   t:`Fix ${num(audit.content?.exact_duplicates?.count)} exact duplicate pages — splits PageRank, confuses Google` },
  { w: psiLcpPoor?(SEV.critical+500):0,                              t:`Fix LCP of ${psi.lcp?.display} (Poor) — direct Google ranking factor for mobile search` },
  { w: SEV.warning+(audit.meta_descriptions?.missing?.count||0),     t:`Write meta descriptions for ${num(audit.meta_descriptions?.missing?.count)} pages to recover lost click-through rate` },
  { w: SEV.warning+(audit.headings?.h1_multiple?.count||0)*5,        t:`Fix multiple H1 tags on ${num(audit.headings?.h1_multiple?.count)} pages — likely a single template code fix` },
  { w: SEV.warning+(audit.images?.missing_alt?.count||0),            t:`Add alt text to ${num(audit.images?.missing_alt?.count)} images — invisible to Google, fails accessibility standards` },
  { w: SEV.warning+(psi.opportunities?.unused_javascript?.savings_kb||0)*3, t:`Remove ${psi.opportunities?.unused_javascript?.savings_kb}KB unused JavaScript — improves LCP by ~${psi.opportunities?.unused_javascript?.savings_lcp_ms||0}ms` },
  { w: SEV.low+(audit.redirect_reports?.chains?.count||0),           t:`Resolve ${num(audit.redirect_reports?.chains?.count)} redirect chains — losing link equity at every extra hop` },
].filter(p=>p.w>SEV.low).sort((a,b)=>b.w-a.w).slice(0,3);
while(priorityCandidates.length<3) priorityCandidates.push({t:'No additional critical issues found',w:0});

// ── RESPONSE CODE CARD DATA (from crawl_overview — authoritative SF numbers) ──
const rcVar   = co.response_codes || {};
const coTotal = co.total_urls_crawled || audit.meta.total_urls_crawled || 1;

const responseCards = [
  { label:'2xx OK',        total:(rcVar.internal_2xx||0)+(rcVar.external_2xx||0)||rcVar.success_2xx||0,  internal:rcVar.internal_2xx||0, external:rcVar.external_2xx||0, col:'#10B981',bg:'#ECFDF5',bdr:'#A7F3D0', sub:'Successfully loaded' },
  { label:'3xx Redirects', total:(rcVar.internal_3xx||0)+(rcVar.external_3xx||0)||rcVar.redirect_3xx||0, internal:rcVar.internal_3xx||0, external:rcVar.external_3xx||0, col:'#F59E0B',bg:'#FFFBEB',bdr:'#FDE68A', sub:'URLs that redirect' },
  { label:'4xx Errors',    total:(rcVar.internal_4xx||0)+(rcVar.external_4xx||0)||rcVar.error_4xx||0,    internal:rcVar.internal_4xx||0, external:rcVar.external_4xx||0, col:'#EF4444',bg:'#FEF2F2',bdr:'#FECACA', sub:'Client errors (404/403)' },
  { label:'5xx Errors',    total:rcVar.internal_5xx||0,                                                  internal:rcVar.internal_5xx||0, external:rcVar.external_5xx||0, col:'#B91C1C',bg:'#FEF2F2',bdr:'#FECACA', sub:'Server errors — urgent' },
];

// ── GLOSSARY DATA ──
const glossaryItems = [
  ['SF','Screaming Frog','A website crawler tool that audits sites by following links and extracting SEO data from every page it finds. Source of all crawl data in this report.'],
  ['PSI','PageSpeed Insights','Google\'s free performance testing tool. Uses Lighthouse and real-user CrUX data. Scores run 0–100.'],
  ['CWV','Core Web Vitals','Three Google ranking signals measuring real-world page experience: LCP, CLS, and INP (or TBT in lab data).'],
  ['LCP','Largest Contentful Paint','Time for the largest visible element (usually hero image) to load. Good = under 2.5s. Direct ranking factor.'],
  ['CLS','Cumulative Layout Shift','Measures visual stability — how much elements shift during load. Good = under 0.1.'],
  ['TBT','Total Blocking Time','Lab proxy for INP. How long JavaScript blocks the main thread. Good = under 200ms.'],
  ['FCP','First Contentful Paint','Time until first text or image renders. Good = under 1.8s.'],
  ['TTFB','Time to First Byte','Time from request to first byte from server. Reflects server speed. Good = under 800ms.'],
  ['SI','Speed Index','How quickly page content visually fills in during load. Good = under 3.4s.'],
  ['TTI','Time to Interactive','When the page becomes fully responsive to user input. Good = under 3.8s.'],
  ['INP','Interaction to Next Paint','Core Web Vital measuring responsiveness to clicks/taps. Replaced FID in March 2024.'],
  ['H1 / H2','Heading Tags','HTML heading levels. H1 = main page topic (one per page). H2 = section headings. Both are ranking signals.'],
  ['404','Not Found Error','Page does not exist. Internal 404s waste Google crawl budget and destroy link equity.'],
  ['5xx','Server Error Codes','500–599 responses — server failed to process the request. Google may stop crawling affected pages.'],
  ['3xx','Redirect Codes','301 = Permanent (passes ~95% link equity). 302 = Temporary. Chains waste crawl budget.'],
  ['4xx','Client Error Codes','400–499 responses including 404 (Not Found), 403 (Forbidden), 410 (Gone).'],
  ['CDN','Content Delivery Network','Servers that serve content from locations closest to each user — reduces latency, improves LCP.'],
  ['HTTPS','HyperText Transfer Protocol Secure','Encrypted HTTP. Google uses HTTPS as a ranking signal. Chrome shows "Not Secure" for HTTP.'],
  ['noindex','No-Index Directive','Tag telling Google not to show a page in search results. Catastrophic if applied to content pages accidentally.'],
  ['canonical','Canonical Tag','Tells Google which URL is the preferred version when duplicate content exists across multiple URLs.'],
  ['robots.txt','Robots Exclusion Standard','File at domain.com/robots.txt telling crawlers which pages to skip. Does not prevent indexing by itself.'],
  ['CrUX','Chrome User Experience Report','Real-user performance data from Chrome. Used in PSI field data. Only available for sites with enough traffic.'],
];

