const ISSUES = {
  errors_4xx:       {icon:'🔴',title:'Broken Pages (4xx Errors)',               sev:'Critical',what:`These pages return "Not Found" or a similar error when visited. Every broken link wastes Google's crawl budget, destroys user experience, and bleeds link equity. Cloudflare cdn-cgi paths are excluded — those are system paths, not real pages.`,fix:`For each broken URL: (1) Restore the page if it should exist, (2) Set up a 301 permanent redirect to the most relevant live alternative, or (3) Remove all internal links pointing to it. The table below shows exactly which pages link to each broken URL.`,impact:'Very High — directly destroys crawlability, link equity, and user trust'},
  errors_5xx:       {icon:'🔴',title:'Server Errors (5xx)',                      sev:'Critical',what:`The server is actively failing on these requests — not missing pages but server crashes. Google encounters these and may stop crawling affected URLs entirely, eventually deindexing them.`,fix:`Check server error logs immediately. Common causes: PHP memory limits, database failures, misconfigured plugins, or server overload. Each 5xx must resolve to a clean 200 response.`,impact:'Very High — Google may deindex affected pages and reduce site-wide crawl frequency'},
  h1_missing:       {icon:'🔴',title:'Missing H1 Headings',                     sev:'Critical',what:`The H1 is the primary heading Google uses to understand what a page is about. Pages without an H1 force Google to guess the topic from context — consistently resulting in lower rankings.`,fix:`Add exactly one H1 to each affected page. Clearly describe the page topic using the primary target keyword naturally. The H1 can differ from the page title — it should be descriptive and specific.`,impact:'Very High — one of the top three strongest on-page ranking signals'},
  lcp_poor:         {icon:'🔴',title:'Poor Largest Contentful Paint (LCP)',      sev:'Critical',what:`LCP measures how long the largest visible element (usually the hero image) takes to load. At ${psi.lcp?.display}, this site is significantly below Google's "Good" threshold of 2.5s. LCP is a Core Web Vital and a direct Google ranking factor since 2021.`,fix:`Priority: (1) Add fetchpriority="high" to the LCP image, (2) Preload it using <link rel="preload">, (3) Remove unused JavaScript (${psi.opportunities?.unused_javascript?.savings_kb||0}KB savings possible), (4) Fix render-blocking CSS (${psi.opportunities?.render_blocking?.savings_ms||0}ms savings possible).`,impact:'Very High — direct Google ranking factor, especially on mobile'},
  titles_missing:   {icon:'🔴',title:'Missing Page Titles',                      sev:'Critical',what:`No title tag exists on these pages. The page title is one of the single strongest on-page ranking signals. Without it, Google has nothing to display in search results and cannot understand the page topic.`,fix:`Add a unique, descriptive title to every page. Keep it 50–60 characters. Place the primary keyword near the beginning.`,impact:'Very High — directly prevents ranking for any keyword'},
  http_pages:       {icon:'🔴',title:'HTTP (Insecure) Pages',                   sev:'Critical',what:`Pages served over HTTP instead of HTTPS. Chrome shows "Not Secure" warnings, destroying user trust. Google officially uses HTTPS as a ranking signal.`,fix:`Ensure all pages are served over HTTPS. Set up 301 redirects from HTTP to HTTPS. Verify your SSL certificate covers all subdomains.`,impact:'Very High — security, user trust, and confirmed Google ranking factor'},
  mixed_content:    {icon:'🔴',title:'Mixed Content (HTTP Resources on HTTPS)',  sev:'Critical',what:`HTTPS pages loading resources over insecure HTTP. Browsers may block these resources from loading, breaking page functionality for visitors.`,fix:`Find all HTTP resource URLs on HTTPS pages. Update every src and href to https://. In WordPress, use Better Search Replace to fix database-wide.`,impact:'Very High — breaks page functionality, undermines HTTPS, triggers browser warnings'},
  exact_duplicates: {icon:'🔴',title:'Exact Duplicate Pages',                   sev:'Critical',what:`Multiple URLs returning identical HTML content. This splits ranking signals between multiple versions and wastes crawl budget on pages that add no value.`,fix:`Set canonical tags on all non-canonical versions pointing to the preferred URL. Consider 301 redirects from duplicate URLs to the canonical version.`,impact:'Very High — splits link equity, ranking unpredictability, wastes crawl budget'},
  h1_duplicate:     {icon:'🟡',title:'Duplicate H1 Tags Across Pages',           sev:'Warning', what:`Multiple pages sharing the same H1 signals to Google that the pages cover the same topic. This directly triggers keyword cannibalisation — your own pages compete against each other in search results.`,fix:`Each page must have a unique H1 reflecting its specific topic. If pages genuinely cover the same topic, consider consolidating them via a canonical or redirect.`,impact:'High — direct keyword cannibalisation and ranking confusion'},
  h1_multiple:      {icon:'🟡',title:'Multiple H1 Tags on Single Pages',         sev:'Warning', what:`Two or more H1 tags on one page dilutes the heading signal. This commonly happens when a template element (footer, sidebar, newsletter) is incorrectly marked as H1 — affecting every page site-wide from one code issue.`,fix:`Almost always a template-level fix. Find the offending element and change it from H1 to H2 or H3 in your theme. One code edit fixes every affected page simultaneously.`,impact:'Medium — dilutes primary heading signal, confuses Google about page topic'},
  h2_missing:       {icon:'🔵',title:'Missing H2 Headings',                     sev:'Low',     what:`H2 headings help Google understand what sections a page contains. Pages without H2s appear as undivided text blocks to search engines, reducing ability to rank for secondary keywords.`,fix:`Add H2 headings to divide content into logical sections. Each H2 should describe that section's topic and can include secondary keywords naturally.`,impact:'Low-Medium — affects content structure signals and secondary keyword ranking'},
  titles_duplicate: {icon:'🟡',title:'Duplicate Page Titles',                   sev:'Warning', what:`Multiple pages sharing identical titles means Google cannot determine which page to rank for a given query — causing direct cannibalisation between your own pages.`,fix:`Write a unique, specific title for every page targeting a different primary keyword. Configure your SEO plugin templates for category and archive pages.`,impact:'High — direct cannibalisation risk, reduces ranking authority per page'},
  titles_too_long:  {icon:'🟡',title:'Page Titles Over 60 Characters',           sev:'Warning', what:`These titles get truncated in Google search results. Users see an incomplete message and Google gives less weight to words after the truncation point.`,fix:`Trim each title to under 60 characters. Place the primary keyword and brand message within the first 50 characters.`,impact:'Medium — reduced CTR and keyword weight on truncated words'},
  meta_missing:     {icon:'🟡',title:'Missing Meta Descriptions',                sev:'Warning', what:`Pages without meta descriptions leave Google to auto-generate a snippet from random page content — often confusing or unappealing to click. This directly reduces organic click-through rate.`,fix:`Write a unique 140–155 character meta description for each affected page. Include the primary keyword and a clear call to action.`,impact:'Medium — lower CTR directly reduces organic traffic even without ranking changes'},
  meta_too_long:    {icon:'🔵',title:'Meta Descriptions Over 155 Characters',    sev:'Low',     what:`Descriptions that exceed Google's display limit get cut off, hiding the key message or CTA from users in search results.`,fix:`Trim each description to under 155 characters. Ensure the most important content appears within the first 140 characters.`,impact:'Low — affects presentation and CTR but not ranking directly'},
  img_no_alt:       {icon:'🟡',title:'Images Missing Alt Text',                  sev:'Warning', what:`Google cannot see images — it relies entirely on alt text to understand image content. Images without alt text are invisible to search engines and fail accessibility standards (WCAG).`,fix:`Add descriptive alt text to every image. Describe what the image shows. Include the primary keyword where natural. Use empty alt="" for purely decorative images.`,impact:'Medium — affects image search rankings, accessibility compliance, and on-page relevance'},
  img_large:        {icon:'🟡',title:'Oversized Images (Over 100KB)',             sev:'Warning', what:`Large unoptimised images are the single most common cause of poor LCP scores. Every page with 200KB+ images is likely failing Google's mobile performance assessment.`,fix:`Compress images over 100KB using Squoosh, TinyPNG, or ShortPixel. Convert to WebP format (25–35% smaller than JPEG). Aim for under 80KB per image. For WordPress, install ShortPixel or Imagify.`,impact:'High — directly affects Core Web Vitals LCP score and mobile ranking'},
  canonical_missing:{icon:'🟡',title:'Missing Canonical Tags',                   sev:'Warning', what:`Without a canonical tag, Google decides on its own which URL version to index — often choosing the wrong one when the same content is accessible via multiple URLs.`,fix:`Add a self-referencing canonical to every page. In WordPress, Yoast SEO or RankMath does this automatically — verify canonical tags are enabled in settings.`,impact:'Medium — duplicate content risk and ranking unpredictability'},
  noindex_pages:    {icon:'🟡',title:'Pages with Noindex Directive',             sev:'Warning', what:`These pages are actively hidden from Google. Correct for admin pages, login pages, and archives. Dangerous if applied to service, product, or blog pages accidentally.`,fix:`Review every URL in this list. Remove noindex from any page that should appear in search results. Focus especially on service pages, products, and high-value content.`,impact:'High — any wrongly noindexed page will never rank regardless of content quality'},
  low_content:      {icon:'🔵',title:'Thin Content Pages (Under 300 Words)',     sev:'Low',     what:`Pages with very little text give Google almost nothing to understand or rank. Too many thin pages across a domain can drag down the overall quality assessment for the entire site.`,fix:`Expand content to at least 300 words with genuinely useful information. Alternatively, consolidate with a related page via 301 redirect if expansion is not viable.`,impact:'Medium — thin content is a known negative quality signal affecting the entire domain'},
  near_duplicates:  {icon:'🟡',title:'Near-Duplicate Content Pages',             sev:'Warning', what:`Pages with very similar content (90%+ similarity) dilute ranking authority and confuse Google about which page to rank for a given keyword.`,fix:`Differentiate content to make each page genuinely unique, or consolidate using canonical tags pointing from the less important version to the main one.`,impact:'Medium — dilutes ranking authority and creates cannibalisation risk'},
  redirect_chains:  {icon:'🟡',title:'Redirect Chains (Multi-Hop Redirects)',    sev:'Warning', what:`A redirect chain is when URL A redirects to URL B, which redirects to URL C. Each extra hop adds user latency, wastes crawl budget, and bleeds link equity with every step.`,fix:`Update source links to point directly to the final destination URL. Every internal link should resolve in one step to a live 200 page.`,impact:'Medium — crawl budget waste, link equity loss, and user latency'},
  redirects_3xx:    {icon:'🔵',title:'Internal Links Pointing to Redirected URLs',sev:'Low',     what:`Internal links point to URLs that redirect rather than linking directly to the final destination. Each redirect adds an unnecessary HTTP request and a marginal crawl cost.`,fix:`Update internal links to point directly to the final canonical destination URL. A CMS search-and-replace tool resolves most cases quickly.`,impact:'Low-Medium — minor crawl inefficiency and marginal latency increase'},
  orphan_pages:     {icon:'🟡',title:'Orphan Pages (No Internal Links)',          sev:'Warning', what:`Pages with zero internal inlinks pointing to them. Google discovers pages mainly through internal links — orphan pages are often not crawled or indexed regularly, even if they exist and have good content.`,fix:`Add internal links to these pages from relevant content pages. Consider adding them to navigation, sitemaps, or related content sections.`,impact:'Medium — orphan pages are poorly crawled, receive no link equity, and may not rank even with good content'},
};

