function buildSFIssues() {
  const sorted = [...(audit.issues_overview||[])].filter(i=>i.count>0)
    .sort((a,b)=>({High:0,Medium:1,Low:2}[a.priority]??3)-({High:0,Medium:1,Low:2}[b.priority]??3));
  let rows = sorted.map((issue,i)=>{
    const tc={Issue:['#FEE2E2','#B91C1C'],Warning:['#FEF3C7','#92400E'],Opportunity:['#EAF3DE','#3B6D11']}[issue.type]||['#F1F5F9','#475569'];
    const pc={High:['#FEE2E2','#B91C1C'],Medium:['#FEF3C7','#92400E'],Low:['#F1F5F9','#475569']}[issue.priority]||['#F1F5F9','#475569'];
    return `<tr style="border-bottom:0.5px solid #E2E8F0;${i%2===1?'background:#F8FAFC;':''}">
      <td style="padding:9px 14px;font-size:12.5px;color:#1E293B;">${safe(issue.name)}</td>
      <td style="padding:9px 14px;"><span style="font-size:10px;font-weight:700;padding:2px 9px;border-radius:99px;background:${tc[0]};color:${tc[1]};">${safe(issue.type)}</span></td>
      <td style="padding:9px 14px;"><span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:99px;background:${pc[0]};color:${pc[1]};">${safe(issue.priority)}</span></td>
      <td style="padding:9px 14px;font-size:13px;font-weight:700;color:#0A1628;">${num(issue.count)}</td>
      <td style="padding:9px 14px;font-size:12px;color:#64748B;">${safe(issue.percent)}%</td>
    </tr>`;
  }).join('');
  const noise = audit.security_header_noise;
  if (noise?.count>0) {
    rows += `<tr style="background:#F8FAFC;border-bottom:0.5px solid #E2E8F0;">
      <td style="padding:9px 14px;font-size:12px;color:#94A3B8;font-style:italic;">+ ${noise.issues?.length||0} server security header warnings (HSTS, X-Frame-Options, CSP, etc.)</td>
      <td style="padding:9px 14px;"><span style="font-size:10px;font-weight:700;padding:2px 9px;border-radius:99px;background:#F1F5F9;color:#475569;">Warning</span></td>
      <td style="padding:9px 14px;"><span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:99px;background:#F1F5F9;color:#475569;">Low</span></td>
      <td style="padding:9px 14px;font-size:13px;font-weight:700;color:#94A3B8;">${num(noise.count)}</td>
      <td style="padding:9px 14px;font-size:12px;color:#94A3B8;">server-level — not SEO critical</td>
    </tr>`;
  }
  return rows;
}

function buildIssueCards() {
  const checks = [
    {key:'errors_4xx',    count:real4xxCount,                                        rows:(audit.broken_link_sources||[]).slice(0,5).map(r=>({url:r.broken_url,code:r.status_code}))},
    {key:'errors_5xx',    count:audit.response_codes?.errors_5xx?.count||0,          rows:audit.response_codes?.errors_5xx?.rows||[]},
    {key:'lcp_poor',      count:psi.lcp?.status==='poor'?1:0,                        rows:[]},
    {key:'http_pages',    count:audit.security?.http_pages?.count||0,                rows:audit.security?.http_pages?.rows||[]},
    {key:'mixed_content', count:audit.security?.mixed_content?.count||0,             rows:[]},
    {key:'exact_duplicates',count:audit.content?.exact_duplicates?.count||0,         rows:audit.content?.exact_duplicates?.rows||[]},
    {key:'titles_missing',count:audit.page_titles?.missing?.count||0,                rows:audit.page_titles?.missing?.rows||[]},
    {key:'h1_missing',    count:audit.headings?.h1_missing?.count||0,                rows:audit.headings?.h1_missing?.rows||[]},
    {key:'h1_duplicate',  count:audit.headings?.h1_duplicate?.count||0,              rows:[]},
    {key:'h1_multiple',   count:audit.headings?.h1_multiple?.count||0,               rows:audit.headings?.h1_multiple?.rows||[]},
    {key:'titles_duplicate',count:audit.page_titles?.duplicate?.count||0,            rows:[]},
    {key:'titles_too_long',count:audit.page_titles?.too_long?.count||0,              rows:audit.page_titles?.too_long?.rows||[]},
    {key:'meta_missing',  count:audit.meta_descriptions?.missing?.count||0,          rows:audit.meta_descriptions?.missing?.rows||[]},
    {key:'meta_too_long', count:audit.meta_descriptions?.too_long?.count||0,         rows:audit.meta_descriptions?.too_long?.rows||[]},
    {key:'h2_missing',    count:audit.headings?.h2_missing?.count||0,                rows:audit.headings?.h2_missing?.rows||[]},
    {key:'img_no_alt',    count:audit.images?.missing_alt?.count||0,                 rows:audit.images?.missing_alt?.rows||[]},
    {key:'img_large',     count:audit.images?.oversized?.count||0,                   rows:audit.images?.oversized?.rows||[]},
    {key:'canonical_missing',count:audit.canonicals?.missing?.count||0,              rows:audit.canonicals?.missing?.rows||[]},
    {key:'noindex_pages', count:audit.directives?.noindex?.count||0,                 rows:audit.directives?.noindex?.rows||[]},
    {key:'low_content',   count:audit.content?.thin_content_300?.count||audit.content?.low_content?.count||0, rows:audit.content?.low_content?.rows||[]},
    {key:'near_duplicates',count:audit.content?.near_duplicates?.count||0,           rows:[]},
    {key:'redirect_chains',count:audit.redirect_reports?.chains?.count||0,           rows:audit.redirect_reports?.chains?.rows||[]},
    {key:'redirects_3xx', count:audit.response_codes?.redirects_3xx?.count||0,       rows:[]},
    {key:'orphan_pages',  count:audit.orphan_pages?.count||0,                        rows:audit.orphan_pages?.rows||[]},
  ];
  const sevOrder={Critical:0,Warning:1,Low:2};
  const active = checks.filter(c=>c.count>0&&ISSUES[c.key]).sort((a,b)=>sevOrder[ISSUES[a.key].sev]-sevOrder[ISSUES[b.key].sev]);
  const sevColors={Critical:{border:'#FECACA',hdr:'#FFF5F5',badge:'#FEE2E2',text:'#B91C1C'},Warning:{border:'#FDE68A',hdr:'#FFFBEB',badge:'#FEF3C7',text:'#92400E'},Low:{border:'#BFDBFE',hdr:'#EFF6FF',badge:'#DBEAFE',text:'#1E40AF'}};
  return active.map(check=>{
    const issue=ISSUES[check.key]; const c=sevColors[issue.sev];
    const sample=(check.rows||[]).slice(0,5);
    let urlRows='';
    if(sample.length>0){
      const rowHtml=sample.map((r,i)=>{
        const url=r.url||r.broken_url||'';
        const extra=r.title?` — ${safe(r.title).substring(0,55)}`:r.word_count!==undefined?` (${r.word_count} words)`:r.size_kb?` (${r.size_kb} KB)`:r.code?` → ${r.code}`:r.hops?` (${r.hops} hops → ${safe(r.final)})`:r.depth?` (depth: ${r.depth})`:'';
        return `<tr style="border-bottom:0.5px solid #E2E8F0;${i%2===1?'background:#F8FAFC;':''}"><td style="padding:6px 12px;font-family:monospace;font-size:10.5px;color:#1D4ED8;word-break:break-all;">${safe(url)}<span style="color:#64748B;font-family:'DM Sans',sans-serif;font-size:10px;">${safe(extra)}</span></td></tr>`;
      }).join('');
      urlRows=`<div style="padding:0 18px 16px;background:white;"><table style="width:100%;border-collapse:collapse;border-radius:8px;overflow:hidden;border:0.5px solid #E2E8F0;"><tr style="background:#1B2B4B;"><th style="padding:8px 12px;text-align:left;font-size:10px;font-weight:600;color:rgba(255,255,255,0.7);text-transform:uppercase;letter-spacing:0.6px;">Sample URLs (${num(check.count)} total)</th></tr>${rowHtml}</table></div>`;
    }
    return `<div style="border-radius:12px;overflow:hidden;border:1px solid ${c.border};margin-bottom:16px;">
      <div style="display:flex;align-items:center;gap:14px;padding:14px 18px;background:${c.hdr};border-bottom:1px solid ${c.border};page-break-inside:avoid;break-inside:avoid;">
        <span style="font-size:16px;">${issue.icon}</span>
        <div>
          <div style="font-family:'Bricolage Grotesque',sans-serif;font-size:14px;font-weight:700;color:#0A1628;">${issue.title}</div>
          <div style="font-size:11px;color:#64748B;margin-top:2px;">${num(check.count)} page${check.count!==1?'s':''} affected</div>
        </div>
        <span style="margin-left:auto;font-size:10px;font-weight:700;padding:4px 12px;border-radius:99px;background:${c.badge};color:${c.text};text-transform:uppercase;letter-spacing:0.5px;white-space:nowrap;">${issue.sev}</span>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;background:white;">
        <div style="padding:16px 18px;border-right:0.5px solid #E2E8F0;"><div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#94A3B8;margin-bottom:8px;">📌 What it means</div><div style="font-size:12.5px;color:#1E293B;line-height:1.65;">${issue.what}</div></div>
        <div style="padding:16px 18px;border-right:0.5px solid #E2E8F0;"><div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#94A3B8;margin-bottom:8px;">🔧 How to fix it</div><div style="font-size:12.5px;color:#1E293B;line-height:1.65;">${issue.fix}</div></div>
        <div style="padding:16px 18px;"><div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:#94A3B8;margin-bottom:8px;">📈 SEO Impact</div><div style="font-size:12.5px;color:#1E293B;line-height:1.65;">${issue.impact}</div></div>
      </div>
      ${urlRows}
    </div>`;
  }).join('');
}

function buildSpeedBars() {
  const buckets=audit.meta.speed_buckets||{};
  const total=Object.values(buckets).reduce((a,b)=>a+b,0)||1;
