    html += `<table style="width:100%;border-collapse:collapse;">
      ${tableHeader('Type / From URL','Redirects To','Code','Pages','Inlinks')}<tbody>
      ${grouped.map((r,i)=>`<tr style="border-bottom:0.5px solid #E2E8F0;${i%2===1?'background:#F8FAFC;':''}">
        <td style="padding:9px 14px;">
          ${r.type==='infrastructure'?`<span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:99px;background:#FEF3C7;color:#92400E;margin-right:6px;">INFRA</span>`:r.type==='internal'?`<span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:99px;background:#DBEAFE;color:#1E40AF;margin-right:6px;">INTERNAL</span>`:''}
          <span style="font-family:monospace;font-size:11px;color:#1D4ED8;word-break:break-all;">${safe(r.label)}</span>
        </td>
        <td style="padding:9px 14px;font-family:monospace;font-size:11px;color:#475569;word-break:break-all;max-width:180px;">${safe(r.redirect_to||'')}</td>
        <td style="padding:9px 14px;"><span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:99px;background:#DBEAFE;color:#1E40AF;">${safe(r.code)}</span></td>
        <td style="padding:9px 14px;font-size:13px;font-weight:600;">${num(r.count)}</td>
        <td style="padding:9px 14px;font-size:13px;">${num(r.total_inlinks)}</td>
      </tr>`).join('')}
      </tbody></table>`;
  }
  if(extCount>0){
    html += `<div style="margin-top:18px;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:10px;padding:14px 18px;">
      <div style="font-size:12px;font-weight:700;color:#64748B;margin-bottom:8px;">
        External Links That Redirect — ${num(extCount)} detected (not your pages to fix)
      </div>
      <div style="font-size:12px;color:#94A3B8;line-height:1.6;">
        Screaming Frog detected <strong style="color:#64748B;">${num(extCount)}</strong> external URLs your site links to that redirect elsewhere
        (e.g. a LinkedIn URL that redirects to a regional version, or a brand URL that redirects to a campaign page).
        The redirect happens on the external site — you cannot control it and it does not affect your SEO score.
        Updating your outgoing links to point to the final destination URL is a minor optional improvement.
      </div>
    </div>`;
  }
  return html;
}

