      </div>
      ${(audit.meta.http_version?.http2||0)<(audit.meta.http_version?.http1||0)?`<div style="margin-top:10px;font-size:12px;color:#92400E;background:#FEF3C7;padding:8px;border-radius:6px;">Upgrade to HTTP/2 for faster parallel loading</div>`:''}
    </div>
    <div style="padding:16px 20px;background:#F8FAFC;border-radius:10px;border:0.5px solid #E2E8F0;">
      <div style="font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:0.7px;color:#94A3B8;margin-bottom:8px;">Robots.txt Blocked Pages</div>
      <div style="font-family:'Bricolage Grotesque',sans-serif;font-size:28px;font-weight:800;color:${(audit.robots_analysis?.count||0)>20?'#F59E0B':'#10B981'};">${num(audit.robots_analysis?.count||0)}</div>
      ${(audit.robots_analysis?.rule_summary||[]).slice(0,2).map(r=>`<div style="font-size:11px;color:#64748B;margin-top:4px;">Rule: <span style="font-family:monospace;font-size:10px;">${safe(r.rule)}</span> (${r.count} pages)</div>`).join('')}
    </div>
  </div>
</div>

<!-- ═══ SECTION 8: SECURITY (only shown if issues found) ═══ -->
${((audit.security?.http_pages?.count||0)+(audit.security?.mixed_content?.count||0))>0?`
<div class="section">
  ${sectionHeader('🔒','Security Issues',(audit.security?.http_pages?.count||0)+(audit.security?.mixed_content?.count||0),'#EF4444')}
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:22px;">
    ${[['HTTP (Insecure) Pages',audit.security?.http_pages?.count||0,'Chrome shows "Not Secure" — ranking penalty'],['Mixed Content Pages',audit.security?.mixed_content?.count||0,'HTTP resources on HTTPS pages']].map(([lbl,val,sub])=>`
    <div style="padding:18px 22px;background:#FEF2F2;border-radius:11px;border:1px solid #FECACA;">
      <div style="font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:0.7px;color:#B91C1C;margin-bottom:5px;">${lbl}</div>
      <div style="font-family:'Bricolage Grotesque',sans-serif;font-size:28px;font-weight:800;color:#B91C1C;">${num(val)}</div>
      <div style="font-size:12px;color:#B91C1C;opacity:0.7;margin-top:4px;">${sub}</div>
    </div>`).join('')}
  </div>
  ${(audit.security?.http_pages?.rows||[]).length>0?`
  <table>${tableHeader('HTTP URL','Status Code','Action Required')}<tbody>
  ${(audit.security.http_pages.rows||[]).slice(0,8).map((r,i)=>`<tr style="border-bottom:0.5px solid #E2E8F0;${i%2===1?'background:#F8FAFC;':''}"><td style="padding:8px 14px;font-family:monospace;font-size:11px;color:#DC2626;word-break:break-all;">${safe(r.url||'')}</td><td style="padding:8px 14px;"><span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:99px;background:#FEE2E2;color:#B91C1C;">${safe(r.status_code||'')}</span></td><td style="padding:8px 14px;font-size:12px;color:#64748B;">Set up 301 redirect to HTTPS version</td></tr>`).join('')}
  </tbody></table>`:''}
</div>`:''}

<!-- ═══ SECTION 9: ISSUE EXPLANATIONS ═══ -->
<div class="section">
  ${sectionHeader('📖','Issue Explanations — What Each Means & How To Fix It',null,'#6366F1')}
  ${buildIssueCards()}
</div>

<!-- ═══ SECTION 10: COMPLETE PRIORITY ACTION PLAN ═══ -->
<div class="section">
  ${sectionHeader('🎯','Complete Priority Action Plan',null,'#EF4444')}
  <table>${tableHeader('#','Action','Scale','Effort','Priority')}<tbody>${buildPriorityRows()}</tbody></table>
  <div style="margin-top:16px;padding:14px 18px;background:#F8FAFC;border-radius:10px;border:0.5px solid #E2E8F0;">
    <div style="font-size:11px;font-weight:600;color:#64748B;margin-bottom:8px;text-transform:uppercase;letter-spacing:0.7px;">Effort Key</div>
    <div style="display:flex;gap:24px;">
      ${[['Low','1 bar — can be done in hours'],['Medium','2 bars — needs a day or two'],['High','3 bars — complex implementation']].map(([lbl,desc])=>`<div style="font-size:12px;color:#64748B;"><strong style="color:#0A1628;">${lbl} effort</strong> — ${desc}</div>`).join('')}
    </div>
  </div>
</div>

<!-- ═══ SECTION 11: ABBREVIATIONS & GLOSSARY ═══ -->
<div class="section">
  ${sectionHeader('📖','Abbreviations & Glossary',null,'#64748B')}
  <div style="font-size:13px;color:#475569;margin-bottom:18px;line-height:1.7;">Reference guide to all technical terms and abbreviations used in this report.</div>
  <div style="display:grid;grid-template-columns:1fr 1fr;border:0.5px solid #E2E8F0;border-radius:12px;overflow:hidden;">
    ${glossaryItems.map(([abbr,full,desc],i)=>`
      <div style="padding:14px 18px;border-bottom:0.5px solid #F1F5F9;${i%2===0?'border-right:0.5px solid #E2E8F0;':''}background:${Math.floor(i/2)%2===0?'white':'#FAFAFA'};">
        <div style="display:flex;align-items:baseline;gap:10px;margin-bottom:5px;">
          <span style="font-family:'DM Mono',monospace;font-size:11px;font-weight:600;color:white;background:#0A1628;padding:2px 9px;border-radius:5px;white-space:nowrap;">${safe(abbr)}</span>
          <span style="font-size:12.5px;font-weight:700;color:#1E293B;">${safe(full)}</span>
        </div>
        <div style="font-size:11.5px;color:#64748B;line-height:1.65;">${safe(desc)}</div>
      </div>`).join('')}
  </div>
</div>

<!-- FOOTER -->
<div style="background:#0A1628;padding:24px 44px;display:flex;align-items:center;justify-content:space-between;">
  <div>
    <div style="font-family:'Bricolage Grotesque',sans-serif;font-size:14px;font-weight:700;color:rgba(255,255,255,0.5);">Generated by <span style="color:white;">${safe(AGENCY.name)}</span></div>
    <div style="font-size:11px;color:rgba(255,255,255,0.3);margin-top:3px;">Confidential — Prepared for ${safe(domain)}</div>
  </div>
  <div style="text-align:center;">
    <div style="font-size:10px;color:rgba(255,255,255,0.25);text-transform:uppercase;letter-spacing:1px;">Audit Date</div>
    <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-top:2px;">${audit.meta.crawl_date}</div>
  </div>
  <div style="text-align:right;font-size:12px;color:rgba(255,255,255,0.4);line-height:1.9;">
    <a href="mailto:${safe(AGENCY.email)}" style="color:rgba(255,255,255,0.65);text-decoration:none;">${safe(AGENCY.email)}</a><br/>
    <span>${safe(AGENCY.website)}</span>
  </div>
</div>

</div>
</body>
</html>`;

return [{ json: { html, website: audit.meta.website, score: audit.health.score, domain } }];
